INSERT INTO posts (slug, title, excerpt, body, tag_id, series, status, pinned, words, read_time, views, published_at, created_at, updated_at) VALUES ('how-to-get-method-parameter-by-windbg', '如何通过WinDbg获取方法参数值', '这篇内容介绍了如何使用 WinDbg 工具来获取方法的参数值。WinDbg 中有多种命令可以帮助我们实现这个目标，包括标准命令、元命令以及扩展命令。其中，通过使用标准命令的 "kP" 命令可以获取方法的参数和参数值，但需要有符号信息支持。此外，文章还介绍了不同的函数调用约定，如cdecl、stdcall、fastcall和X64约定，以及如何在内存中查找方法的参数值。文章提供了详细的示例和调试过程', '# 引入

我们在调试的过程中，经常会通过查看方法的输入与输出来确定这个方法是否异常。那么我们要怎么通过 WinDbg 来获取方法的参数值呢？

WinDbg 中主要包含三种命令：标准命令、元命令（以 . 开始）和扩展命令（以 ! 开始）。

# 通过标准命令获取参数值

**k 命令**可以获取栈回溯。

其中 **kP** 可以把参数和参数值都以函数原型格式显示出来，但是需要有符号。如下：

```
0:000> kP
 # Child-SP          RetAddr               Call Site
00 0000001b7b0fdb78 00007ffc718366fb     ntdll!NtCreateUserProcess
01 0000001b7b0fdb80 00007ffc718732f6     KERNELBASE!CreateProcessInternalW+0x115b
02 0000001b7b0ff510 00007ffc728560c4     KERNELBASE!CreateProcessW+0x66
03 0000001b7b0ff580 00007ff614a61960     KERNEL32!CreateProcessWStub+0x54
04 0000001b7b0ff5e0 00007ff614a62419     CreateProcessWithCpp!main(
            int argc = 0n1, 
            wchar_t ** argv = 0x00000208`0b637d00)+0xe0 [C:Usersfrendsourcereposdebug-testAdavageDebugCreateProcessWithCppCreateProcessWithCpp.cpp @ 20] 
05 0000001b7b0ff800 00007ff614a622be     CreateProcessWithCpp!invoke_main(void)+0x39 [D:a_work1ssrcvctoolscrtvcstartupsrcstartupexe_common.inl @ 79] 
06 0000001b7b0ff850 00007ff614a6217e     CreateProcessWithCpp!__scrt_common_main_seh(void)+0x12e [D:a_work1ssrcvctoolscrtvcstartupsrcstartupexe_common.inl @ 288] 
07 0000001b7b0ff8c0 00007ff614a624ae     CreateProcessWithCpp!__scrt_common_main(void)+0xe [D:a_work1ssrcvctoolscrtvcstartupsrcstartupexe_common.inl @ 331] 
08 0000001b7b0ff8f0 00007ffc7285244d     CreateProcessWithCpp!mainCRTStartup(
            void * __formal = 0x0000001b`7aeca000)+0xe [D:a_work1ssrcvctoolscrtvcstartupsrcstartupexe_main.cpp @ 17] 
09 0000001b7b0ff920 00007ffc740cdf88     KERNEL32!BaseThreadInitThunk+0x1d
0a 0000001b7b0ff950 0000000000000000     ntdll!RtlUserThreadStart+0x28

0:000> dc 0x00000208`0b637d00
00000208`0b637d00  0b637d10 00000208 00000000 00000000  .}c.............
00000208`0b637d10  555c3a43 73726573 6572665c 735c646e  C:Usersfrends
00000208`0b637d20  6372756f 65725c65 5c736f70 75626564  ourcereposdebu
00000208`0b637d30  65742d67 415c7473 61766164 65446567  g-testAdavageDe
00000208`0b637d40  5c677562 5c343678 75626544 72435c67  bugx64DebugCr
00000208`0b637d50  65746165 636f7250 57737365 43687469  eateProcessWithC
