INSERT INTO posts (slug, title, excerpt, body, tag_id, series, status, pinned, words, read_time, views, published_at, created_at, updated_at) VALUES ('how-to-boot-with-windows', 'Windows 启动过程分析', '这篇文章介绍了Windows操作系统的启动过程，分为加载内核、内核初始化和应用程序初始化三个部分。启动过程概览涵盖了两种方式：传统的BIOS和UEFI。文章详细解释了BIOS的加载过程，包括POST、Bootstrap Loader、BIOS和CMOS Setup。然后介绍了NT内核的加载，包括实模式和保护模式下的操作。最后，提到了从系统分区读取boot.ini文件和检查hiberfil.sys文', '# 引言

启动过程是我们了解操作系统的第一个环节。了解 Windows 的启动过程，可以帮助我们解决一些启动的问题，也能帮助我们了解 Windows 的整体结构。

以下内容将分为【加载内核】、【内核初始化】和【应用程序初始化】三个部分。

![](https://media.frendguo.com/2024/09/e590afe58aa8e8bf87e7a88be6a682e8a788-1024x763.png)
*启动过程概览*

# 加载内核

![](https://media.frendguo.com/2024/09/image-14.png)

如 [启动过程概览](https://www.notion.so/6060eb3f3af14251bb3c3bc8b47c45ee#fc23f33168554a67a68dbcf6fabd10f5) 所示，加载过程分为两种方式。传统的 BIOS（*Basic Input/Output System*）和 UEFI（*Unified Extensible Firmware Interface*）。这两种方式大致相似，本文以 BIOS 为例来说明引导说过。

## 加载 BIOS

当开机键被按下后，电源将执行初始化，确保电源可靠后，主板上的硬件电路给 CPU 发复位（reset）信号。

CPU 收到复位信号后，将从 RAM 中读取指令执行。此时内存中是没有任何指令需要执行的。于是 CPU 就去 BIOS ROM 中特定的位置（FFFF0H）中执行指令，这个指令是一个跳转指令 ，将告诉 CPU 真正的 BIOS 程序所在的位置。跳转指令如下：

```
jmp far f000:e05b ; 跳转到0xfe05b执行
```

## 运行 BIOS

BIOS 主要包含以下四个部分的程序：

-   **POST**：*Power On Self Test。*用于检测硬件的可用性，如果有问题，会发出蜂鸣声并且停止进行下一步。
-   **Bootstrap Loader**：用来确定操作系统的位置，帮助引导操作系统的启动。此程序会遍历所有的存储设备的0盘0道1扇区的内容，如果这一扇区最后两字节的内容是0x55 0xaa，则认为它是启动区（也就是 MBR，Master Boot Record），并将扇区的内容（也就是ntldr）复制到内存0x7c00位置。至此，代码的控制权就交给了操作系统代码了。

> Windows 的做法是，让引导扇区中的代码读入其他扇区的数据，然后跳转到下一个扇区的代码区。这样就可以不受单个引导扇区长度的限制，这种做法相当于将第一个引导扇区当做一个加载器（loader），而真正完成引导扇区功能的扇区随后被加载进来并执行。这一过程对于 MBR 是透明的，从而保持良好的兼容性。

-   **BIOS**：用于软件和硬件的通信。
-   **CMOS Setup**：一个配置程序，用于配置操作系统的时间、日期和密码等

## 加载 NT 内核

此时代码的控制权已经来到了 ntldr（也可以是 WinLoad 或者 os loader），此时处理器还运行实模式下，所以 ntldr 也分为两部分：实模式代码和保护模式代码。

在实模式下，ntldr 的主要任务是：

-   完成在实模式下执行的初始化。比如清除键盘缓冲区。
-   为切换到保护模式做好基本的环境准备。
-   将处理器切换到保护模式下，然后将控制权交给保护模式下的代码。

在保护模式下，需要完成以下步骤：

1.  由于虚拟机制转译机制还未就绪，首先要做的就是把物理内存管理起来。采用一个内存描述符数组将每一段内存的大小和用途记录下来，然后打开页面映射机制
2.  继续执行其他的初始化工作。包含 I/O 设备的初始化等
3.  从系统分区的根目录下读取 boot.ini 文件。并检查是否存在有效的 hiberfil.sys 文件，如果存在，则将引导过程转移到休眠系统的恢复过程。否则，将解析 boot.ini 文件 。
4.  运行 NTDETECT.COM 程序。此程序运行在实模式下，它将利用 BIOS 来查询系统的基本设备和配置信息，并收集起来。在引导后期，将其存放到注册表 HKLMHARDWAREDESCRIPTION 下。
5.  加载 ntoskrnl.exe、hal（默认为 hal.dll，具体是哪个映像文件，在 boot.ini 中会有记录），再通过加载注册表的 system 储巢，即 WINDOWSsystem32configsystem 文件 拿到哪些设备驱动程序必须被加载进来，然后再把必要的设备驱动加载进来。
6.  此时加载的准备工作基本就绪，将准备的信息构造成一个参数块 LOADER\_PARAMETER\_BLOCK.如下定义来自 WRK。

```
typedef struct _LOADER_PARAMETER_BLOCK {
    LIST_ENTRY LoadOrderListHead; // 加载的模块链表，每个元素都为 KLDR_DATA_TABLE_ENTRY
    LIST_ENTRY MemoryDescriptorListHead; // 内存描述符链表，每个元素都为 MEMORY_ALLOCATION_DESCRIPTOR
    LIST_ENTRY BootDriverListHead;// 引导驱动程序链表，每个元素都为 BOOT_DRIVER_LIST_ENTRY
    ULONG_PTR KernelStack;// 内核栈顶
    ULONG_PTR Prcb;// 进程环境，指向一个进程控制块
    ULONG_PTR Process;// 初始进程，EPROCESS
    ULONG_PTR Thread;// 初始线程，ETHREAD
    ULONG RegistryLength;// System 储巢的长度
    PVOID RegistryBase;// System 储巢的基地址
    PCONFIGURATION_COMPONENT_DATA ConfigurationRoot;// 配置树，包含 ISA、磁盘和 ACPI 的配置数据
    PCHAR ArcBootDeviceName;// 引导分区的 ARC 名称
    PCHAR ArcHalDeviceName;// 系统分区的 ARC 名称
    PCHAR NtBootPathName;// OS 目录的路径名称，比如“Windows”
    PCHAR NtHalPathName;// OS 加载器的路径名称，比如“”
    PCHAR LoadOptions;// 引导选项，来自 boot.ini
    PNLS_DATA_BLOCK NlsData;// 包含 ANSI 代码页、OEM 代码页和 Unicode 码表
    PARC_DISK_INFORMATION ArcDiskInformation;// 所有磁盘的签名结构
    PVOID OemFontFile;// OEM 字体文件
    struct _SETUP_LOADER_BLOCK *SetupLoaderBlock;// 网络引导或文字模式安装引导
    PLOADER_PARAMETER_EXTENSION Extension;// 扩展部分

    union {
        I386_LOADER_BLOCK I386;
        // ALPHA_LOADER_BLOCK Alpha;
        // IA64_LOADER_BLOCK Ia64;
    } u;
} LOADER_PARAMETER_BLOCK, *PLOADER_PARAMETER_BLOCK;
```

1.  最后，ntlrd 将控制权交给 ntoskrnl.exe 的入口函数。表示内核加载完成。

# 内核初始化

![](https://media.frendguo.com/2024/09/image-15.png)

到这里，接下来的过程，我们就可以通过 WRK 来观察具体的过程了。

ntoskrnl.exe 的入口函数是 \_KiSystemStartup，可以顺着这个方法往下看。

整个初始化分为两个阶段：Phase0 和 Phase1。

![](https://media.frendguo.com/2024/09/image-16.png)

阶段1的初始化入口是 Phase1InitializationDiscard 方法。此方法也是做了各种初始化，具体可以去看代码。由于其时间比较长，所以内部做了一个进度估计。

---

待 阶段1 完成初始化，执行体的各个组件都进入了一个正常状态。但只有内核是没有意义的，系统必须让应用程序跑起来。应用程序的启动就得依赖刚启动的 smss 进程继续了。

# 应用初始化

现在控制权来到了 smss，smss 是 Windows 中一个重要的进程。

![](https://media.frendguo.com/2024/09/image-17-1024x753.png)

smss 还会继续完成引导过程。在内核初始化期间，只有 System 储巢被加载到内存当中了。其他的就得由 smss 来加载。其他初始化必要的工作，可以参看 HKLMSYSTEMCurrentControlSetControlSession Manager 。

注册表中能发现一些有趣的子键。

![](https://media.frendguo.com/2024/09/image-18-1024x410.png)

-   建立系统的全局环境变量，这些环境变量由 Environment 键下的值指定
-   运行在启动时执行的程序，这些程序由 BootExecute 值指定
-   执行启动时的文件删除或重命名任务，这由 FileRenameOperations 子键来指定
-   启动 Windows 子系统进程（csrss.exe）。子系统进程的命令行字符串由 SubSystems 子键的 Windows 值指定

然后 smss 便会启动 winlogon 进程，随后接下来的引导便交由 winlogon 进程了。 winlogon 主要职责如下：

1.  创建初始窗口
2.  创建登录桌面和默认桌面
3.  启动服务控制管理器（SCM，Service Control Manager）进程（services.exe）
4.  启动本地安全权威子系统（lsass）进程

在登录过程的最后，winlogon 检查注册表 HKLMSOFTWAREMicrosoftWindows NTCurrentVersionWinlogonUserinit 的值，并创建一个进程来运行该值字符串。该值串的默认值为 userinit.exe 程序的路径。Userinit 进程加载当前登录用户的轮廓，然后检查 HKCUSoftwareMicrosoftWindows NTCurrentVersionWinlogonShell 的值，并创建一个进程来运行该值字符串；如果该值不存在，则运行 HKLMSOFTWAREMicrosoftWindows NTCurrentVersionWinlogonShell 的值，其默认值为 explorer.exe。然后，userinit 进程退出。由于当前登录会话的 Shell 程序（explorer.exe）已经启动，因此用户可以在桌面上操作了。

---

至此，引导就全部结束了。', 'win', NULL, 'published', 0, 2152, 8, 327, 1653236280, 1653236280, 1728890482);
INSERT INTO posts (slug, title, excerpt, body, tag_id, series, status, pinned, words, read_time, views, published_at, created_at, updated_at) VALUES ('understand-apc', '深入理解 APC', '这篇内容讨论了在Windows操作系统中如何使用APC（异步过程调用）来实现异步操作。它介绍了在Win32 API中使用ReadFileEx函数来演示APC的用法，并解释了在内核层面如何处理APC。文章还提到了用户APC和内核APC之间的区别，并详细描述了在内核模式和用户模式之间切换时如何执行用户APC。
总结来说，这段内容主要讨论了Windows操作系统中的APC机制以及如何在用户层调用Read', '💡 以下代码主要参考 reactos 和 win2k3（泄露代码）x86 代码。Win10 中有部分修改，但原理一致，这里先不进行讨论。

# 引入

APC（[**Asynchronous Procedure Calls**](https://learn.microsoft.com/en-us/windows/win32/sync/asynchronous-procedure-calls)）：异步过程调用

应用程序中经常用到 APC。这里以 ReadFileEx 为例来描述下，Win32 API 中是怎么用 APC 的。

ReadFileEx 是通过 APC 机制来实现异步读取文件的功能的。先看看 ReadFileEx 的代码：

```
BOOL WINAPI
ReadFileEx(IN HANDLE hFile,
           IN LPVOID lpBuffer,
           IN DWORD nNumberOfBytesToRead OPTIONAL,
           IN LPOVERLAPPED lpOverlapped,
           IN LPOVERLAPPED_COMPLETION_ROUTINE lpCompletionRoutine)
{
    LARGE_INTEGER Offset;
    NTSTATUS Status;

    Offset.u.LowPart = lpOverlapped->Offset;
    Offset.u.HighPart = lpOverlapped->OffsetHigh;
    lpOverlapped->Internal = STATUS_PENDING;

    Status = NtReadFile(hFile,
                        NULL,
                        ApcRoutine,
                        lpCompletionRoutine,
                        (PIO_STATUS_BLOCK)lpOverlapped,
                        lpBuffer,
                        nNumberOfBytesToRead,
                        &Offset,
                        NULL);

    if (!NT_SUCCESS(Status))
    {
        BaseSetLastNTError(Status);
        return FALSE;
    }

    return TRUE;
}
```

其中 `lpCompletionRoutine` 是指向在读取操作完成且调用线程处于可警报等待状态时调用的完成例程的指针。说人话就是，这是当文件读取完成时的回调。

我们再来看看 `NtReadFile` ，因为其比较长，就截取关键代码：

```
VOID WINAPI
ApcRoutine(PVOID ApcContext,
           PIO_STATUS_BLOCK IoStatusBlock,
           ULONG Reserved)
{
    DWORD dwErrorCode;
    LPOVERLAPPED_COMPLETION_ROUTINE lpCompletionRoutine =
        (LPOVERLAPPED_COMPLETION_ROUTINE)ApcContext;

    dwErrorCode = RtlNtStatusToDosError(IoStatusBlock->Status);
    lpCompletionRoutine(dwErrorCode,
                        IoStatusBlock->Information,
                        (LPOVERLAPPED)IoStatusBlock);
}

NTSTATUS
NTAPI
NtReadFile(IN HANDLE FileHandle,
           IN HANDLE Event OPTIONAL,
           IN PIO_APC_ROUTINE ApcRoutine OPTIONAL,
           IN PVOID ApcContext OPTIONAL,
           OUT PIO_STATUS_BLOCK IoStatusBlock,
           OUT PVOID Buffer,
           IN ULONG Length,
           IN PLARGE_INTEGER ByteOffset OPTIONAL,
           IN PULONG Key OPTIONAL)
{
......
        /* Allocate the IRP */
    Irp = IoAllocateIrp(DeviceObject->StackSize, FALSE);
        ...
        Irp->Overlay.AsynchronousParameters.UserApcRoutine = ApcRoutine;
    Irp->Overlay.AsynchronousParameters.UserApcContext = ApcContext;
        ...
        /* Perform the call */
    return IopPerformSynchronousRequest(DeviceObject,
                                        Irp,
                                        FileObject,
                                        TRUE,
                                        PreviousMode,
                                        Synchronous,
                                        IopReadTransfer);
}

NTSTATUS
NTAPI
IopPerformSynchronousRequest(IN PDEVICE_OBJECT DeviceObject,
                             IN PIRP Irp,
                             IN PFILE_OBJECT FileObject,
                             IN BOOLEAN Deferred,
                             IN KPROCESSOR_MODE PreviousMode,
                             IN BOOLEAN SynchIo,
                             IN IOP_TRANSFER_TYPE TransferType)
{
        ...
        /* Call the driver */
    Status = IoCallDriver(DeviceObject, Irp);
        ....
}
```

可以看到在 `NtReadFile` 中，实际上将应用层的 callback 作为 apccontext 来进行的。

ApcRoutine 是预置的一个 APC 例程，实现也比较简单，其实就是对例程的一个封装执行。运行在 APC\_LEVEL

`NtReadFile` 中就是将用户层的 callback 打包到 irp 中，然后发给底层的驱动，待驱动调用 IoCompleteRequest 来完成这个 irp。

再来看看 `IoCompleteRequest` ，由于 `IoCompleteRequest` → `IofCompleteRequest` →`IopCompleteRequest` ，所以这里放部分 `IopCompleteRequest` 的相关代码：

💡 `IofCompleteRequest` 和`IopCompleteRequest` 的区别是：`IofCompleteRequest` 是`IopCompleteRequest` 的快速调用版本，具有更优的性能。`IopCompleteRequest` 是原始方法。

```
VOID
NTAPI
IopCompleteRequest(IN PKAPC Apc,
                   IN PKNORMAL_ROUTINE* NormalRoutine,
                   IN PVOID* NormalContext,
                   IN PVOID* SystemArgument1,
                   IN PVOID* SystemArgument2)
{
                ...
                /* Now check if a User APC Routine was requested */
        if (Irp->Overlay.AsynchronousParameters.UserApcRoutine)
        {
            /* Initialize it */
            KeInitializeApc(&Irp->Tail.Apc,
                            KeGetCurrentThread(),
                            CurrentApcEnvironment,
                            IopFreeIrpKernelApc,
                            IopAbortIrpKernelApc,
                            (PKNORMAL_ROUTINE)Irp->
                            Overlay.AsynchronousParameters.UserApcRoutine,
                            Irp->RequestorMode,
                            Irp->
                            Overlay.AsynchronousParameters.UserApcContext);

            /* Queue it */
            KeInsertQueueApc(&Irp->Tail.Apc, Irp->UserIosb, NULL, 2);
        }
                ...
}
```

在 `IoCompleteRequest` 中，将用户层的 callback 和上文提到的 ApcRoutine 塞进去 irp 的 APC 队列中。待返回到用户层之前，进行执行，以调用用户层的 callback 来实现异步回调。

总结下 `ReadFileEx` ，用户层在调用`ReadFileEx` 的时候，传入一个 callback，`NtReadFile` 将 callback 作为 apccontext 塞入 irp 给到底层驱动处理。待底层驱动处理完成后，通过调用 `IoCompleteRequest` 将 callback 构造成一个 apc，待返回用户层前夕进行调用，以完成异步调用。

# APC 关键结构

APC 主要分为`内核 APC` 和 `用户 APC` 。内核 APC 就是指在内核空间执行的 APC，用户 APC 就是在用户空间执行的 APC。

## 内核 APC

先来看看支撑内核 APC 的结构：

APC 跟线程是密不可分的，所以我们先从 `KTHREAD` 中看看 APC 相关的结构：

`KTHREAD` 部分结构如下：

```
Typedef struct _KTHREAD
{
   …
   KAPC_STATE  ApcState;//表示本线程当前使用的APC状态（即apc队列的状态）
   KAPC_STATE  SavedApcState;//表示保存的原apc状态，备份用
   KAPC_STATE* ApcStatePointer[2];//状态数组，包含两个指向APC状态的指针
   UCHAR ApcStateIndex;//0或1，指当前的ApcState在ApcStatePointer数组中的索引位置
   UCHAR ApcQueueable;//指本线程的APC队列是否可插入apc
   ULONG KernelApcDisable;//禁用标志
     //专用于挂起操作的APC（这个函数在线程一得到调度就重新进入等待态,等待挂起计数减到0）
     //Win10 中已经改成 SchedulerApc
   KAPC SuspendApc;
   …   
}KTHREAD;
```

`KAPC_STATE` 的结构如下：

```
Typedef struct _KAPC_STATE //APC队列的状态描述符
{
   LIST_ENTRY  ApcListHead[2];//每个线程有两个apc队列
   PKPROCESS Process;//当前线程所在的进程
   BOOL KernelApcInProgress;//指示本线程是否当前正在 内核apc
   BOOL KernelApcPending;//表示内核apc队列中是否有apc
   BOOL UserApcPending;//表示用户apc队列中是否apc
}
```

最重要的 `_KAPC` 的结构如下：

```
typedef struct _KAPC
{
  UCHAR Type;//结构体的类型
  UCHAR Size;//结构体的大小
  struct _KTHREAD *Thread;//目标线程
  LIST_ENTRY ApcListEntry;//用来挂入目标apc队列
  PKKERNEL_ROUTINE KernelRoutine;//该apc的内核总入口
  PKRUNDOWN_ROUTINE RundownRoutine;
  PKNORMAL_ROUTINE NormalRoutine;//该apc的用户空间总入口或者用户真正的内核apc函数
  PVOID NormalContext;//真正用户提供的用户空间apc函数或者用户真正的内核apc函数的context*
  PVOID SystemArgument1;//挂入时的附加参数1。真正用户apc的context*
  PVOID SystemArgument2;//挂入时的附加参数2
  CCHAR ApcStateIndex;//指要挂入目标线程的哪个状态时的apc队列
  KPROCESSOR_MODE ApcMode;//指要挂入用户apc队列还是内核apc队列
  BOOLEAN Inserted;//表示本apc是否已挂入队列
} KAPC, *PKAPC;
```

需要注意的是：

-   `KernelRoutine` ：无论是什么 APC，都会首先执行这个函数
-   `RundownRoutine` ：当插入 APC 失败的时候，会执行这个函数
-   `NormalRoutine` ：在内核 APC 下，这是 APC 例程，`NormalContext` 是其 context；在用户 APC 下，这是统一的例程，上述例子中是 `ApcRoutine` ，`NormalContext` 才是用户的 APC 函数，`SystemArgument1` 才是 APC 的 context。

# APC 函数执行时机

我们先看看从内核返回用户时的流程：

以下是部分伪代码：

```
KiSystemService()//int 2e的isr，内核服务函数总入口，注意这个函数可以嵌套、递归！！！
{
    SaveTrap();//保存trap现场
        Sti  //开中断
        ---------------上面保存完寄存器等现场后，开始查SST表调用系统服务------------------
        FindTableCall();
        ---------------------------------调用完系统服务函数后------------------------------
        Move  esp,kthread.TrapFrame; //将栈顶回到trap帧结构体处
        Cli  //关中断
        If(上次模式==UserMode)
        {
        Call  KiDeliverApc //遍历执行本线程的内核APC和用户APC队列中的所有APC函数
        //清理Trap帧，恢复寄存器现场
        Iret   //返回用户空间
        }
        Else
        {
           //返回到原call处后面的那条指令处
        }
}
```

从上述伪代码可以看出，内核代码执行完后切换到用户模式的时候，就会通过 `KiDeliverApc` 来进行扫描 APC 并执行。

通过搜索`KiDeliverApc` 调用，可以看到从异常、中断返回、ThreadSwap 都有调用。可以从相关函数中找到（包括但不限于）：

-   `KiCheckForKernelApcDelivery`
-   `HalpApcInterruptHandler`
-   `KiExitV86Trap`
-   `KiCheckForApcDelivery`
-   `KiApcInterrupt`
-   `KiSwapThread`
-   `KiExitDispatcher`

💡 `HalpApcInterruptHandler` 就是 apc 作为一种软中断的 ISR。

于是就可以来看看最核心的 `KiDeliverApc` 的调用了（简化了的）：

```
/*++
 * @name KiDeliverApc
 * @implemented @NT4
 *
 *     The KiDeliverApc routine is called from IRQL switching code if the
 *     thread is returning from an IRQL >= APC_LEVEL and Kernel-Mode APCs are
 *     pending.
 *
 * @param DeliveryMode
 *        Specifies the current processor mode.
 *
 * @param ExceptionFrame
 *        Pointer to the Exception Frame on non-i386 builds.
 *
 * @param TrapFrame
 *        Pointer to the Trap Frame.
 *
 * @return None.
 *
 * @remarks First, Special APCs are delivered, followed by Kernel-Mode APCs and
 *          User-Mode APCs. Note that the TrapFrame is only valid if the
 *          delivery mode is User-Mode.
 *          Upon entry, this routine executes at APC_LEVEL.
 *
 *--*/
VOID
NTAPI
KiDeliverApc(IN KPROCESSOR_MODE DeliveryMode,//指要执行哪个apc队列中的函数
             IN PKEXCEPTION_FRAME ExceptionFrame,//传入的是NULL
             IN PKTRAP_FRAME TrapFrame)//即将返回用户空间前的Trap现场帧
{
    PKTHREAD Thread = KeGetCurrentThread();
    PKPROCESS Process = Thread->ApcState.Process;
    OldTrapFrame = Thread->TrapFrame;
    Thread->TrapFrame = TrapFrame;
    Thread->ApcState.KernelApcPending = FALSE;
        if (Thread->SpecialApcDisable) goto Quickie;
        //先固定执行掉内核apc队列中的所有apc函数
    while (!IsListEmpty(&Thread->ApcState.ApcListHead[KernelMode]))
    {
        KiAcquireApcLockAtApcLevel(Thread, &ApcLock);//锁定apc队列
        ApcListEntry = Thread->ApcState.ApcListHead[KernelMode].Flink;//队列头部中的apc
        Apc = CONTAINING_RECORD(ApcListEntry, KAPC, ApcListEntry);
        KernelRoutine = Apc->KernelRoutine;//内核总apc函数
        NormalRoutine = Apc->NormalRoutine;//用户自己真正的内核apc函数
        NormalContext = Apc->NormalContext;//真正内核apc函数的context*
        SystemArgument1 = Apc->SystemArgument1;
        SystemArgument2 = Apc->SystemArgument2;
        if (NormalRoutine==NULL) //称为Special Apc,少见
        {
            RemoveEntryList(ApcListEntry);//关键，移除队列
            Apc->Inserted = FALSE;
            KiReleaseApcLock(&ApcLock);
            //执行内核中的总apc函数
            KernelRoutine(Apc,&NormalRoutine,&NormalContext,
                          &SystemArgument1,&SystemArgument2);
        }
        Else //典型，一般程序员都会提供一个自己的内核apc函数
        {
            if ((Thread->ApcState.KernelApcInProgress) || (Thread->KernelApcDisable))
            {
                KiReleaseApcLock(&ApcLock);
                goto Quickie;
            }
            RemoveEntryList(ApcListEntry); //关键，移除队列
            Apc->Inserted = FALSE;
            KiReleaseApcLock(&ApcLock);
//执行内核中的总apc函数
            KernelRoutine(Apc,
                          &NormalRoutine,//注意，内核中的总apc可能会在内部修改NormalRoutine
                          &NormalContext,
                          &SystemArgument1,
                          &SystemArgument2);
            if (NormalRoutine)//如果内核总apc没有修改NormalRoutine成NULL
            {
                Thread->ApcState.KernelApcInProgress = TRUE;//标记当前线程正在执行内核apc
                KeLowerIrql(PASSIVE_LEVEL);
                //直接调用用户提供的真正内核apc函数
                NormalRoutine(NormalContext, SystemArgument1, SystemArgument2);
                KeRaiseIrql(APC_LEVEL, &ApcLock.OldIrql);
            }
            Thread->ApcState.KernelApcInProgress = FALSE;
        }
    }
    //上面的循环，执行掉所有内核apc函数后，下面开始执行用户apc队列中的第一个apc
    if ((DeliveryMode == UserMode) &&
         !(IsListEmpty(&Thread->ApcState.ApcListHead[UserMode])) &&
         (Thread->ApcState.UserApcPending))
    {
        KiAcquireApcLockAtApcLevel(Thread, &ApcLock);//锁定apc队列
        Thread->ApcState.UserApcPending = FALSE;

        ApcListEntry = Thread->ApcState.ApcListHead[UserMode].Flink;//队列头
        Apc = CONTAINING_RECORD(ApcListEntry, KAPC, ApcListEntry);
        KernelRoutine = Apc->KernelRoutine; //内核总apc函数
        NormalRoutine = Apc->NormalRoutine; //用户空间的总apc函数
        NormalContext = Apc->NormalContext;//用户真正的用户空间apc函数
        SystemArgument1 = Apc->SystemArgument1;//真正apc的context*
        SystemArgument2 = Apc->SystemArgument2;
        RemoveEntryList(ApcListEntry);//关键，移除队列
        Apc->Inserted = FALSE;
        KiReleaseApcLock(&ApcLock);
        KernelRoutine(Apc,
                      &NormalRoutine,// 注意，内核中的总apc可能会在内部修改NormalRoutine
                      &NormalContext,
                      &SystemArgument1,
                      &SystemArgument2);
        if (!NormalRoutine)
            KeTestAlertThread(UserMode);
        Else //典型，准备提前回到用户空间调用用户空间的总apc函数
        {
            KiInitializeUserApc(ExceptionFrame,//NULL
                                TrapFrame,//Trap帧的地址
                                NormalRoutine, //用户空间的总apc函数
                                NormalContext, //用户真正的用户空间apc函数
                                SystemArgument1, //真正apc的context*
                                SystemArgument2);
        }
    }
Quickie:
    Thread->TrapFrame = OldTrapFrame;
}
```

可以看到，这个函数既处理内核 APC，也处理用户 APC。一次执行会遍历所有的内核 APC，但只会执行一次的用户 APC。

那其他的用户 APC 就不管了吗？当然不是的，其实每次尝试正式回到用户态的时候都会执行一遍。也就是循环执行，每次循环都会将内核 APC 队列执行完，然后执行一个用户 APC。

所以，**总体流程**是这样的：

扫描执行内核apc队列所有apc -> 执行用户apc队列中一个apc -> 再次扫描执行内核apc队列所有apc -> 执行用户apc队列中下一个apc -> 再次扫描执行内核apc队列所有apc -> 再次执行用户apc队列中下一个apc如此循环，直到将用户apc队列中的所有apc都执行掉。

上面提到这段代码是在内核模式返回用户模式之前会执行的，也就是内核模式下，那要怎么执行用户模式的代码呢？

嗯，答案就在 `KiInitializeUserApc` 里面了。我们先来看看它干了什么：

```
VOID
KiInitializeUserApc(IN PKEXCEPTION_FRAME ExceptionFrame,
                    IN PKTRAP_FRAME TrapFrame,//原真正的断点现场帧
                    IN PKNORMAL_ROUTINE NormalRoutine,
                    IN PVOID NormalContext,
                    IN PVOID SystemArgument1,
                    IN PVOID SystemArgument2)
{
        Context.ContextFlags = CONTEXT_FULL | CONTEXT_DEBUG_REGISTERS;
        //将原真正的Trap帧打包保存在一个Context结构中
    KeTrapFrameToContext(TrapFrame, ExceptionFrame, &Context);
    _SEH2_TRY
    {
        AlignedEsp = Context.Esp & ~3;//对齐4B
                //为用户空间中KiUserApcDisatcher函数的参数腾出空间（4个参数+ CONTEXT + 8B的seh节点）
        ContextLength = CONTEXT_ALIGNED_SIZE + (4 * sizeof(ULONG_PTR));
        Stack = ((AlignedEsp - 8) & ~3) - ContextLength;//8表示seh节点的大小
        //模拟压入KiUserApcDispatcher函数的4个参数
        *(PULONG_PTR)(Stack + 0 * sizeof(ULONG_PTR)) = (ULONG_PTR)NormalRoutine;
        *(PULONG_PTR)(Stack + 1 * sizeof(ULONG_PTR)) = (ULONG_PTR)NormalContext;
        *(PULONG_PTR)(Stack + 2 * sizeof(ULONG_PTR)) = (ULONG_PTR)SystemArgument1;
        *(PULONG_PTR)(Stack + 3 * sizeof(ULONG_PTR)) = (ULONG_PTR)SystemArgument2;
        //将原真正trap帧保存在用户栈的一个CONTEXT结构中，方便以后还原
        RtlCopyMemory( (Stack + (4 * sizeof(ULONG_PTR))),&Context,sizeof(CONTEXT));

        //强制修改当前Trap帧中的返回地址与用户栈地址（偏离原来的返回路线）
        TrapFrame->Eip = (ULONG)KeUserApcDispatcher;//关键，新的返回断点地址
        TrapFrame->HardwareEsp = Stack;//关键，新的用户栈顶
        TrapFrame->SegCs = Ke386SanitizeSeg(KGDT_R3_CODE, UserMode);
        TrapFrame->HardwareSegSs = Ke386SanitizeSeg(KGDT_R3_DATA, UserMode);
        TrapFrame->SegDs = Ke386SanitizeSeg(KGDT_R3_DATA, UserMode);
        TrapFrame->SegEs = Ke386SanitizeSeg(KGDT_R3_DATA, UserMode);
        TrapFrame->SegFs = Ke386SanitizeSeg(KGDT_R3_TEB, UserMode);
        TrapFrame->SegGs = 0;
        TrapFrame->ErrCode = 0;
        TrapFrame->EFlags = Ke386SanitizeFlags(Context.EFlags, UserMode);
        if (KeGetCurrentThread()->Iopl) TrapFrame->EFlags |= EFLAGS_IOPL;
    }
    _SEH2_EXCEPT((RtlCopyMemory(&SehExceptRecord, _SEH2_GetExceptionInformation()->ExceptionRecord, sizeof(EXCEPTION_RECORD)),    EXCEPTION_EXECUTE_HANDLER))
    {
        SehExceptRecord.ExceptionAddress = (PVOID)TrapFrame->Eip;
        KiDispatchException(&SehExceptRecord,ExceptionFrame,TrapFrame,UserMode,TRUE);
    }
    _SEH2_END;
}
```

这段代码的核心逻辑就是修改 TrapFram 的执行地址（在这里就是返回地址）为用户空间的 `KiUserApcDisatcher` ，并把原 TrapFram 保存到用户空间下，然后将参数模拟压入这个函数的栈中，这样就可以模拟执行 `KiUserApcDisatcher` 了。

💡 可以看到这里整个执行块被一个 try 块包起来了，这是因为谁也不知道用户代码会发生什么问题，这里可不能崩溃。

于是，我们再来看看 `KiUserApcDisatcher` 干了啥：

```
KiUserApcDisatcher(NormalRoutine,
                   NormalContext,
                   SysArg1,
                   SysArg2
)
{
   Lea eax,[esp+ CONTEXT_ALIGNED_SIZE+16]   //eax指向seh异常节点的地址
   Mov ecx,fs:[TEB_EXCEPTION_LIST]
   Mov edx,offset KiUserApcExceptionHandler
   --------------------------------------------------------------------------------------
   Mov [eax],ecx //seh节点的next指针成员
   Mov [eax+4],edx //she节点的handler函数指针成员
   Mov fs:[TEB_EXCEPTION_LIST],eax
   --------------------上面三条指令在栈中构造一个8B的标准seh节点-----------------------
   Pop eax //eax=NormalRoutine（即IntCallUserApc这个总apc函数）
   Lea edi,[esp+12] //edi=栈中保存的CONTEXT结构的地址
   Call eax //相当于call IntCallUserApc（NormalContext，SysArg1，SysArg2）

   Mov ecx,[edi+ CONTEXT_ALIGNED_SIZE]
   Mov fs:[ TEB_EXCEPTION_LIST],ecx   //撤销栈中的seh节点

   Push TRUE  //表示回到内核后需要继续检测执行用户apc队列中的apc函数
   Push edi  //传入原栈帧的CONTEXT结构的地址给这个函数，以做恢复工作
   Call NtContinue   //调用这个函数重新进入内核（注意这个函数正常情况下是不会返回到下面的）
   ----------------------------------华丽的分割线-------------------------------------------
   Mov esi,eax
   Push esi
   Call RtlRaiseStatus  //若ZwContinue返回了，那一定是内部出现了异常
   Jmp StatusRaiseApc
   Ret 16
}
```

每当要执行一个用户空间apc时，都会‘提前’偏离原来的路线返回用户空间的这个函数处去执行用户的 apc。在执行这个函数前，会先构造一个 seh 节点，也即相当于把这个函数的调用放在 try 块中保护。这个函数内部会调用`IntCallUserApc`，执行完真正的用户 apc 函数后，调用`NtContinue`重返内核。

💡 这里的 `IntCallUserApc` 跟前面提到的 `ApcRoutine` 是一致的。

`NtContinue` 代码如下：

```
NTSTATUS NtContinue(CONTEXT* Context, //原真正的TraFrame 
                    BOOL TestAlert  //指示是否继续执行用户apc队列中的apc函数
)
{
   Push ebp  //此时ebp=本系统服务自身的TrapFrame地址
   Mov ebx,PCR[KPCR_CURRENT_THREAD] //ebx=当前线程的KTHREAD对象地址
   Mov edx,[ebp+KTRAP_FRAME_EDX] //注意TrapFrame中的这个edx字段不是用来保存edx的
   Mov [ebx+KTHREAD_TRAP_FRAME],edx //将当前的TrapFrame改为上一个TrapFrame的地址
   Mov ebp,esp
   Mob eax,[ebp] //eax=本系统服务自身的TrapFrame地址
   Mov ecx,[ebp+8] /本函数的第一个参数，即Context
   Push eax
   Push NULL
   Push ecx
   Call KiContinue  //call KiContinue(Context*,NULL,TrapFrame*)
   Or eax,eax
   Jnz error
   Cmp dword ptr[ebp+12],0 //检查TestAlert参数的值
   Je DontTest
   Mov al,[ebx+KTHREAD_PREVIOUS_MODE]
   Push eax
   Call KeTestAlertThread  //检测用户apc队列是否为空
   DontTest：
   Pop ebp
   Mov esp,ebp
   Jmp KiServiceExit2 //返回用户空间（返回前，又会去扫描执行apc队列中的下一个用户apc）
}
```

`KiContinue` 代码如下：

```
NTSTATUS
KiContinue(IN PCONTEXT Context,//原来的断点现场
           IN PKEXCEPTION_FRAME ExceptionFrame,
           IN PKTRAP_FRAME TrapFrame) //NtContinue自身的TrapFrame地址
{
    NTSTATUS Status = STATUS_SUCCESS;
    KIRQL OldIrql = APC_LEVEL;
    KPROCESSOR_MODE PreviousMode = KeGetPreviousMode();
if (KeGetCurrentIrql() < APC_LEVEL) 
KeRaiseIrql(APC_LEVEL, &OldIrql);
    _SEH2_TRY
    {
        if (PreviousMode != KernelMode)
            KiContinuePreviousModeUser(Context,ExceptionFrame,TrapFrame);//恢复成原TrapFrame
        else
        {
            KeContextToTrapFrame(Context,ExceptionFrame,TrapFrame,Context->ContextFlags,
                                 KernelMode); //恢复成原TrapFrame
        }
    }
    _SEH2_EXCEPT(EXCEPTION_EXECUTE_HANDLER)
    {
        Status = _SEH2_GetExceptionCode();
    }
    _SEH2_END;
if (OldIrql < APC_LEVEL)
 KeLowerIrql(OldIrql);
    return Status;
}
```

`KiContinuePreviousModeUser` 代码如下：

```
VOID
KiContinuePreviousModeUser(IN PCONTEXT Context,//原来的断点现场
                           IN PKEXCEPTION_FRAME ExceptionFrame,
                           IN PKTRAP_FRAME TrapFrame)//NtContinue自身的TrapFrame地址
{
    CONTEXT LocalContext;
    ProbeForRead(Context, sizeof(CONTEXT), sizeof(ULONG));
    RtlCopyMemory(&LocalContext, Context, sizeof(CONTEXT));
Context = &LocalContext;
//看到没，将原Context中的成员填写到NtContinue系统服务的TrapFrame帧中（也即修改成原来的TrapFrame）
    KeContextToTrapFrame(&LocalContext,ExceptionFrame,TrapFrame,
                         LocalContext.ContextFlags,UserMode);
}
```

`KeTestAlertThread` 代码如下：

```
BOOLEAN  KeTestAlertThread(IN KPROCESSOR_MODE AlertMode)
{
    PKTHREAD Thread = KeGetCurrentThread();
    KiAcquireApcLock(Thread, &ApcLock);
    OldState = Thread->Alerted[AlertMode];
    if (OldState)
        Thread->Alerted[AlertMode] = FALSE;
    else if ((AlertMode != KernelMode) &&
 (!IsListEmpty(&Thread->ApcState.ApcListHead[UserMode])))
    {
        Thread->ApcState.UserApcPending = TRUE;//关键。又标记为不空，从而又去执行用户apc
    }
    KiReleaseApcLock(&ApcLock);
    return OldState;
}
```

如上，上面的函数，就把NtContinue的TrapFrame强制还原成原来的TrapFrame，以好‘正式’返回到用户空间的真正断点处。

💡 不过在返回用户空间前，又要去扫描用户 apc 队列，若仍有用户 apc 函数，就先执行掉内核 apc 队列中的所有 apc 函数，然后又偏离原来的返回路线，【提前】返回到用户空间的`KiUserApcDispatcher`函数去执行用户 apc，这是一个不断循环的过程。可见，`NtContinue`这个函数不仅含有继续回到原真正用户空间断点处的意思，还含有继续执行用户 apc 队列中下一个 apc 函数的意思。

---

特别地，在 `KeLowerIrql` 也会执行 apc，这个函数在从当前irql降到目标irql时，会按irql高低顺序执行各个软中断的isr。

```
#define PASSIVE_LEVEL           0
#define APC_LEVEL               1
#define DISPATCH_LEVEL          2
#define CMCI_LEVEL              5
```

> 比如，当调用`KfLowerIrql`要将 cpu 的 irql 从 `CMCI_LEVEL` 降低到 `PASSIVE_LEVEL` 时，这个函数中途会先看看当前 cpu 是否收到了`CMCI_LEVEL`级的软中断，若有，就调用那个软中断的 isr 处理之。然后，再检查是否收到有 `DISPATCH_LEVEL`级的软中断，若有，调用那个软中断的isr处理之，然后，检查是否有 APC 中断，若有，同样处理之。最后，降到目标 irql，即`PASSIVE_LEVEL`。 换句话说，在 irql 的降低过程中会一路检查、处理中途的软中断。Cpu 数据结构中有一个 IRR 字段，即表示当前 cpu 累积收到了哪些级别的软中断。

# APC 如何插入

下面这个 Win32 API 可以用来手动插入一个 apc 到指定线程的用户 apc 队列中。

```
DWORD 
QueueUserAPC(PAPCFUNC pfnAPC, HANDLE hThread, ULONG_PTR dwData)
{
  NTSTATUS Status;
  //调用对应的系统服务
  Status = NtQueueApcThread(hThread,//目标线程
 IntCallUserApc,//用户空间中的总apc入口
 pfnAPC,//用户自己真正提供的apc函数
(PVOID)dwData,//SysArg1=context*
 NULL);//SysArg2=NULL
  if (!NT_SUCCESS(Status))
  {
    SetLastErrorByStatus(Status);
    return 0;
  }
  return 1;
}

NTSTATUS
NtQueueApcThread(IN HANDLE ThreadHandle,//目标线程
                 IN PKNORMAL_ROUTINE ApcRoutine,//用户空间中的总apc
                 IN PVOID NormalContext,//用户自己真正的apc函数
                 IN PVOID SystemArgument1,//用户自己apc的context*
                 IN PVOID SystemArgument2)//其它
{
    PKAPC Apc;
    PETHREAD Thread;
    NTSTATUS Status = STATUS_SUCCESS;
    Status = ObReferenceObjectByHandle(ThreadHandle,THREAD_SET_CONTEXT,PsThreadType,
                                       ExGetPreviousMode(), (PVOID)&Thread,NULL);
    //分配一个apc结构，这个结构最终在PspQueueApcSpecialApc中释放
    Apc = ExAllocatePoolWithTag(NonPagedPool |POOL_QUOTA_FAIL_INSTEAD_OF_RAISE,
                                sizeof(KAPC),TAG_PS_APC);
    //构造一个apc
    KeInitializeApc(Apc,
                    &Thread->Tcb,//目标线程
                    OriginalApcEnvironment,//目标apc状态（此服务固定为OriginalApcEnvironment）
                    PspQueueApcSpecialApc,//内核apc总入口
                    NULL,//Rundown Rounine=NULL
                    ApcRoutine,//用户空间的总apc
                    UserMode,//此系统服务固定插入到用户apc队列
                    NormalContext);//用户自己真正的apc函数
    //插入到目标线程的用户apc队列
    KeInsertQueueApc(Apc,
                     SystemArgument1,//插入时的附加参数1，此处为用户自己apc的context*
                     SystemArgument2, //插入时的附加参数2
                     IO_NO_INCREMENT)//表示不予调整目标线程的调度优先级
    return Status;
}

//这个函数用来构造一个要插入指定目标队列的apc对象
VOID
KeInitializeApc(IN PKAPC Apc,
                IN PKTHREAD Thread,//目标线程
                IN KAPC_ENVIRONMENT TargetEnvironment,//目标线程的目标apc状态
                IN PKKERNEL_ROUTINE KernelRoutine,//内核apc总入口
                IN PKRUNDOWN_ROUTINE RundownRoutine OPTIONAL,
                IN PKNORMAL_ROUTINE NormalRoutine,//用户空间的总apc
                IN KPROCESSOR_MODE Mode,//要插入用户apc队列还是内核apc队列
                IN PVOID Context) //用户自己真正的apc函数
{
    Apc->Type = ApcObject;
    Apc->Size = sizeof(KAPC);
    if (TargetEnvironment == CurrentApcEnvironment)//CurrentApcEnvironment表示使用当前apc状态
        Apc->ApcStateIndex = Thread->ApcStateIndex;
    else
        Apc->ApcStateIndex = TargetEnvironment;
    Apc->Thread = Thread;
    Apc->KernelRoutine = KernelRoutine;
    Apc->RundownRoutine = RundownRoutine;
    Apc->NormalRoutine = NormalRoutine;
    if (NormalRoutine)//if 提供了用户空间总apc入口
    {
        Apc->ApcMode = Mode;
        Apc->NormalContext = Context;
    }
    Else//若没提供，肯定是内核模式
    {
        Apc->ApcMode = KernelMode;
        Apc->NormalContext = NULL;
    }
    Apc->Inserted = FALSE;//表示初始构造后，尚未挂入apc队列
}

BOOLEAN
KeInsertQueueApc(IN PKAPC Apc,IN PVOID SystemArgument1,IN PVOID SystemArgument2,
                 IN KPRIORITY PriorityBoost)
{
    PKTHREAD Thread = Apc->Thread;
    KLOCK_QUEUE_HANDLE ApcLock;
    BOOLEAN State = TRUE;
    KiAcquireApcLock(Thread, &ApcLock);//插入过程需要独占队列
    if (!(Thread->ApcQueueable) || (Apc->Inserted))//检查队列是否可以插入apc
        State = FALSE;
    else
    {
        Apc->SystemArgument1 = SystemArgument1;//记录该apc的附加插入时的参数
        Apc->SystemArgument2 = SystemArgument2; //记录该apc的附加插入时的参数
        Apc->Inserted = TRUE;//标记为已插入队列
       //插入目标线程的目标apc队列（如果目标线程正处于睡眠状态，可能会唤醒它）
        KiInsertQueueApc(Apc, PriorityBoost); 
    }
    KiReleaseApcLockFromDpcLevel(&ApcLock);
    KiExitDispatcher(ApcLock.OldIrql);//可能引发一次线程切换，以立即切换到目标线程执行apc
    return State;
}

VOID FASTCALL
KiInsertQueueApc(IN PKAPC Apc,IN KPRIORITY PriorityBoost)//唤醒目标线程后的优先级增量
{
    PKTHREAD Thread = Apc->Thread;
    BOOLEAN RequestInterrupt = FALSE;
    if (Apc->ApcStateIndex == InsertApcEnvironment) //if要动态插入到当前的apc状态队列
        Apc->ApcStateIndex = Thread->ApcStateIndex; 
    ApcState = Thread->ApcStatePointer[(UCHAR)Apc->ApcStateIndex];//目标状态
ApcMode = Apc->ApcMode;
//先插入apc到指定位置
    /* 插入位置的确定：分三种情形
     * 1) Kernel APC with Normal Routine or User APC : Put it at the end of the List
     * 2) User APC which is PsExitSpecialApc : Put it at the front of the List
     * 3) Kernel APC without Normal Routine : Put it at the end of the No-Normal Routine Kernel APC list
    */
    if (Apc->NormalRoutine)//有NormalRoutine的APC都插入尾部（用户模式发来的线程终止APC除外）
    {
        if ((ApcMode == UserMode) && (Apc->KernelRoutine == PsExitSpecialApc))
        {
            Thread->ApcState.UserApcPending = TRUE;
            InsertHeadList(&ApcState->ApcListHead[ApcMode],&Apc->ApcListEntry);
        }
        else
            InsertTailList(&ApcState->ApcListHead[ApcMode],&Apc->ApcListEntry);
    }
    Else //无NormalRoutine的特殊类APC（内核APC），少见
    {
        ListHead = &ApcState->ApcListHead[ApcMode];
        NextEntry = ListHead->Blink;
        while (NextEntry != ListHead)
        {
            QueuedApc = CONTAINING_RECORD(NextEntry, KAPC, ApcListEntry);
            if (!QueuedApc->NormalRoutine) break;
            NextEntry = NextEntry->Blink;
        }
        InsertHeadList(NextEntry, &Apc->ApcListEntry);//插在这儿
    }

    //插入到相应的位置后，下面检查Apc状态是否匹配
    if (Thread->ApcStateIndex == Apc->ApcStateIndex)//if 插到了当前apc状态的apc队列中
    {
        if (Thread == KeGetCurrentThread())//if就是给当前线程发送的apc
        {
            ASSERT(Thread->State == Running);//当前线程肯定没有睡眠，这不废话吗？
            if (ApcMode == KernelMode)
            {
                Thread->ApcState.KernelApcPending = TRUE;
                if (!Thread->SpecialApcDisable)//发出一个apc中断，待下次降低irql时将执行apc
                    HalRequestSoftwareInterrupt(APC_LEVEL); //关键
            }
        }
        Else //给其他线程发送的内核apc
        {
            KiAcquireDispatcherLock();
            if (ApcMode == KernelMode)
            {
                Thread->ApcState.KernelApcPending = TRUE;
                if (Thread->State == Running)
                    RequestInterrupt = TRUE;//需要给它发出一个apc中断
                else if ((Thread->State == Waiting) && (Thread->WaitIrql == PASSIVE_LEVEL) &&
                         !(Thread->SpecialApcDisable) && (!(Apc->NormalRoutine) ||
                         (!(Thread->KernelApcDisable) &&
                         !(Thread->ApcState.KernelApcInProgress))))
                {
                    Status = STATUS_KERNEL_APC;
                    KiUnwaitThread(Thread, Status, PriorityBoost);//临时唤醒目标线程执行apc
                }
                else if (Thread->State == GateWait) …
            }
            else if ((Thread->State == Waiting) && (Thread->WaitMode == UserMode) &&
                     ((Thread->Alertable) || (Thread->ApcState.UserApcPending)))
            {
                Thread->ApcState.UserApcPending = TRUE;
                Status = STATUS_USER_APC;
                KiUnwaitThread(Thread, Status, PriorityBoost);//强制唤醒目标线程
            }
            KiReleaseDispatcherLockFromDpcLevel();
            KiRequestApcInterrupt(RequestInterrupt, Thread->NextProcessor);
        }
    }
}
```

这个函数既可以给当前线程发送 apc，也可以给目标线程发送 apc。若给当前线程发送内核 apc 时，会立即请求发出一个 apc 中断。若给其他线程发送 apc 时，可能会唤醒目标线程。', 'win', NULL, 'published', 0, 5689, 20, 245, 1693977420, 1693977420, 1728890486);
INSERT INTO posts (slug, title, excerpt, body, tag_id, series, status, pinned, words, read_time, views, published_at, created_at, updated_at) VALUES ('thread-sync-methods', '线程同步的方式', '讨论了在Windows内核编程中如何进行多线程同步。它介绍了一些常用的同步原语，包括互锁操作、分发器对象、互斥量、快速互斥量、信号量、事件、执行体资源、自旋锁等。这些原语用于确保多线程之间的协调工作，以避免竞争条件和死锁。需要注意的是，不同的同步原语适用于不同的情况，选择正确的原语对于编写高效的多线程代码非常重要。', '# 背景

多线程在现代计算机上已经是随处可见了，保证多线程正常、高效的协调工作就显得尤为重要了。

内核也考虑到这个问题了，所以提供了一些原语来帮助达成适当的同步。

# 对比

| **原语或技术** | **说明** | **相关方法** | **备注** |
| --- | --- | --- | --- |
| **互锁操作** | 一种CPU的特殊指令（CPU内联函数） | InterlockedIncrement/InterlockedDecrement/InterlockedAdd/InterlockedExchange/InterlockedCompareExchange | 常用于无锁编程中，可以在不使用软件对象的前提下执行复杂的原子操作。 |
| **分发器对象（可等待对象）** | 此类型对象将分为有信号和无信号。它们被称为“可等待的”是因为线程 可以在这样的对象上待直至它们变成有信号。在等待期间线程不会消耗CPU周期，因为它处于等待状态。 | KeWaitForSingleObject/KeWaitForMultipleObjects | 从等待函数返回的所有值传递给NT\_SUCCESS宏都返回真。 |
| **互斥量（mutant）** | 互斥量是一种经典的对象，用于解决多个线程中的某个线程在任何时刻访问共享资源的标准问题。 | KeInitializeMutex/KeReleaseMutex | 互斥量在使用前必须初始化；使用完后必须释放互斥量。可以通过 RAII 来优雅实现。 |
| **快速互斥量** | 快速互斥量是传统互斥量的一个替代，提供了更好的性能。 | ExInitializeFastMutex/ExAcquireFastMutex/ExAcquireFastMutexUnsafe（IRQL 为 APC\_LEVEL）/ExReleaseFastMutex/ExReleaseFastMutexUnsafe | 快速互斥量不能递归地获取。这么做会造成死锁；快速互斥量被获取之后，CPU IRQL会提升到APC\_LEVEL（1）。这会阻止该线程上APC的传递；快速互斥量只能无限等待—无法指定超时值。 |
| **信号量** | 信号量的主要目标是用来限制某些东西，比如队列的长度。 | KeInitializeSemaphore/KeReleaseSemaphore | 一个最大值为一的信号量是否相当于一个互斥量？首先，这看上去 是正确的，但其实不然。信号量没有所有权，一个线程获取的信号量可以被另一个线程释放。 |
| **事件** | 事件封装了一个布尔型的标志—要么真（有信号）要么假（无信号）。事件的主要目的是在某事发生时发出信号，提供执行流上的同 步。 | KeInitializeEvent/KeResetEvent/KeClearEvent | 事件有两种类型：通知事件（手动重置）和同步事件（自动重置）。 |
| **执行体资源** | 适合单写多读场景的一种同步原语，是另一种特殊对象，并不属于分发器对象。 | ExInitializeResourceLite/ExAcquireResourceExclusiveLite/ExAcquireResourceSharedLite/ExReleaseResourceList | 调用获取和释放函数的先决条件是**必须禁止通常的内核APC**。可以调用KeEnterCriticalRegion/KeLeaveCriticalRegion来做到。 |
| **自旋锁（针对高IRQL）** | 自旋锁是内存中的一个简单位，通过API提供原子化的测试和修改操作。当CPU想要获取自旋锁而它当前并不自由的话，CPU会一直在自旋锁上自旋，等待它被另一个CPU释放。 | KeAcquireSpinLock/KeReleaseSpinLock/KeAcquireSpinLockAtDpcLevel/KeReleaseSpinLockFromDpcLevel/KeAcquireInterruptSpinLock/KeReleaseInterruptSpinLock | 如果获取了自旋锁，千万记得在同一个函数中释放它，否则就有死 锁的风险。类似的还有 **排队自旋锁。** |', 'win', NULL, 'published', 0, 922, 3, 69, 1663700340, 1663700340, 1728890489);
INSERT INTO posts (slug, title, excerpt, body, tag_id, series, status, pinned, words, read_time, views, published_at, created_at, updated_at) VALUES ('create-and-terminal-process', '进程的创建和终止', '这篇内容主要讲述了如何创建一个进程，分为用户态和内核态两部分。在用户态，通过一系列方法如CreateProcess、CreateProcessAsUser等，确定进程的参数和标志。然后在内核态，通过NtCreateUserProcess创建用户模式的进程。进程创建过程包括参数转换、打开要执行的镜像文件、创建进程对象等步骤。其中还提到了镜像劫持（IFEO）的原理，可以通过注册表实现打开一个进程时实际', '![](https://media.frendguo.com/2024/09/image-19-1024x485.png)

