17 0000000002aaf070 00007ff8cb93945a     windows_storage!CShellLink::_ResolveAndInvoke+0x202
18 0000000002aaf230 00007ff8ce15630c     windows_storage!CShellLink::InvokeCommand+0x1aa
19 0000000002aaf310 00007ff8ce15618d     SHELL32!HDXA_LetHandlerProcessCommandEx+0x10c
1a 0000000002aaf420 00007ff8ce3709d5     SHELL32!CDefFolderMenu::InvokeCommand+0x13d
1b 0000000002aaf780 00007ff8ce6244f9     SHELL32!SHInvokeCommandOnContextMenu2+0x1f5
