```

### 4.2 问题

-   如果在冻结后，丢失了 job 的句柄，则无法恢复

### 4.3 示例

```
#define JOB_OBJECT_OPERATION_FREEZE 1

HANDLE ByJobObjectFreeze(DWORD dwProcessId)
{
    HANDLE hProcess = OpenProcess(PROCESS_ALL_ACCESS, FALSE, dwProcessId);
    if (hProcess == NULL)
    {
        std::cout << "OpenProcess failed" << std::endl;
        return nullptr;
    }

    HANDLE hJob = CreateJobObject(NULL, NULL);
    if (hJob == NULL)
    {
        std::cout << "CreateJobObject failed" << std::endl;
        CloseHandle(hProcess);
        return nullptr;
    }

    JOBOBJECT_FREEZE_INFORMATION jfi;
    jfi.Flags = JOB_OBJECT_OPERATION_FREEZE;
    jfi.Freeze = true;

    // (JOBOBJECTINFOCLASS)18 <-> JobObjectFreezeInformation
    if (!NT_SUCCESS(NtSetInformationJobObject(hJob, (JOBOBJECTINFOCLASS)18, &jfi, sizeof(jfi))))
    {
        std::cout << "SetInformationJobObject failed" << std::endl;
        CloseHandle(hJob);
        CloseHandle(hProcess);
        return nullptr;
    }

    if (!AssignProcessToJobObject(hJob, hProcess))
    {
        std::cout << "AssignProcessToJobObject failed" << std::endl;
        CloseHandle(hJob);
        CloseHandle(hProcess);
        return nullptr;
    }

    std::cout << "Process freeze" << std::endl;
    CloseHandle(hProcess);

    return hJob;
}

void ByJobObjectUnFreeze(DWORD dwProcessId, HANDLE hObj) {
    HANDLE hProcess = OpenProcess(PROCESS_ALL_ACCESS, FALSE, dwProcessId);
    if (hProcess == NULL)
    {
        std::cout << "OpenProcess failed" << std::endl;
        return;
    }

    JOBOBJECT_FREEZE_INFORMATION jfi;
    jfi.Flags = JOB_OBJECT_OPERATION_FREEZE;
    jfi.Freeze = false;

    // (JOBOBJECTINFOCLASS)18 <-> JobObjectFreezeInformation
    if (!NT_SUCCESS(NtSetInformationJobObject(hObj, (JOBOBJECTINFOCLASS)18, &jfi, sizeof(jfi))))
    {
        std::cout << "SetInformationJobObject failed" << std::endl;
        CloseHandle(hObj);
        CloseHandle(hProcess);
        return;
    }

    std::cout << "Process unfreeze" << std::endl;
    CloseHandle(hProcess);
}
```

## 5\. `NtChangeProcessState`

此 API 只能在 Win11 以上使用

首先通过 `NtCreateProcessStateChange` 创建一个句柄，然后通过 `NtChangeProcessState` 修改进程状态

如果释放了 `NtCreateProcessStateChange` 创建的句柄，则会自动恢复

### 5.1 原理

这里直接看看调用堆栈：

```
Call Site
nt!KiInsertQueueApc
nt!KiSuspendThread+0x6f
nt!KiFreezeSingleThread+0x71
nt!KeFreezeProcess+0x9f
nt!PsFreezeProcess+0x2c
nt!NtChangeProcessState+0x179
nt!KiSystemServiceCopyEnd+0x25
ntdll!NtChangeProcessState+0x14
```

基本上可以看出，其本质上都是通过插入 apc 来实现进程挂起。

### 5.2 问题

-   不能暂停内核代码。由于是塞了个 APC 到线程中去，所以是需要等内核代码执行完成后才会执行到 APC 中，才有可能被暂停（加之 APC 队列中可能还存在其他 APC）

### 5.3 示例

```

#define PROCESS_STATE_CHANGE_STATE (0x0001)
#define PROCESS_STATE_ALL_ACCESS STANDARD_RIGHTS_ALL | PROCESS_STATE_CHANGE_STATE

// 此方法只在 win11 以后的版本才有
HANDLE ByProcessStateChangeFreeze(DWORD processId) {
    HANDLE hProcess = OpenProcess(PROCESS_ALL_ACCESS, FALSE, processId);
    if (hProcess == NULL)
    {
        std::cout << "OpenProcess failed" << std::endl;
        return nullptr;
    }

    HANDLE hProcessStateChange = nullptr;
    NTSTATUS status = NtCreateProcessStateChange(&hProcessStateChange, PROCESS_SET_INFORMATION | PROCESS_STATE_ALL_ACCESS, nullptr, hProcess, NULL);
    if (!NT_SUCCESS(status)) {
        std::cout << "NtCreateProcessStateChange failed, status is : " << status << std::endl;
        CloseHandle(hProcess);
        return nullptr;
    }

    status = NtChangeProcessState(hProcessStateChange, hProcess, PROCESS_STATE_CHANGE_TYPE::ProcessStateChangeSuspend, NULL, 0, 0);
    if (!NT_SUCCESS(status)) {
        std::cout << "NtChangeProcessState failed, status is : " << status << std::endl;
        CloseHandle(hProcessStateChange);
        CloseHandle(hProcess);
        return nullptr;
    }

    std::cout << "Process freeze" << std::endl;
    CloseHandle(hProcess);
}

void ByProcessStateChangeResume(DWORD processId, HANDLE hProcessStateChange) {
    HANDLE hProcess = OpenProcess(PROCESS_ALL_ACCESS, FALSE, processId);
    if (hProcess == NULL)
    {
        std::cout << "OpenProcess failed" << std::endl;
        return;
    }

    NTSTATUS status = NtChangeProcessState(hProcessStateChange, hProcess, PROCESS_STATE_CHANGE_TYPE::ProcessStateChangeResume, NULL, 0, 0);
    if (!NT_SUCCESS(status)) {
        std::cout << "NtChangeProcessState failed, status is: " << status << std::endl;
        CloseHandle(hProcessStateChange);
        CloseHandle(hProcess);
        return;
    }

    std::cout << "Process unfreeze" << std::endl;
    CloseHandle(hProcessStateChange);
    CloseHandle(hProcess);
}
```', 'win', NULL, 'published', 0, 3399, 12, 686, 1716524820, 1716524820, 1728890553);
INSERT INTO posts (slug, title, excerpt, body, tag_id, series, status, pinned, words, read_time, views, published_at, created_at, updated_at) VALUES ('understanding-critical-performance-fields-in-windows-apps', 'Windows 应用性能关键字段解析', '解释了 Windows 应用程序的各种性能指标，包括 CPU 内核使用率和用户使用率、内存使用量（私有字节、虚拟大小、页面错误、工作集）、I/O 操作（读取、写入、其他 I/O）以及 GPU 使用率（专用、共享、已提交内存）等', '# 背景

在各种软件中（任务管理器、ProcessExplorer等）中经常能看到各种关于 CPU、内存和网络部分的各个字段。

这里就做一个统一的汇总和解释：

# CPU 部分

<table><tbody><tr><td><strong>字段</strong></td><td><strong>解释</strong></td></tr><tr><td><strong>CPU</strong></td><td>当前 CPU 使用率</td></tr><tr><td><strong>CPU (user)</strong></td><td>用户模式下的 CPU 使用率</td></tr><tr><td><strong>CPU (kernel)</strong></td><td>内核模式下的 CPU 使用率</td></tr><tr><td><strong>CPU (average)</strong></td><td>平均 CPU 使用率</td></tr><tr><td><strong>CPU (relative)</strong></td><td>相对 CPU 使用率</td></tr><tr><td><strong>Cycles</strong></td><td>CPU 周期数</td></tr><tr><td><strong>Cycles delta</strong></td><td>CPU 周期变化量</td></tr><tr><td><strong>Context switches</strong></td><td>上下文切换次数</td></tr><tr><td><strong>Context switches delta</strong></td><td>上下文切换变化量</td></tr><tr><td><strong>Kernel time</strong></td><td>内核模式下的 CPU 时间</td></tr><tr><td><strong>Kernel delta</strong></td><td>内核模式下的 CPU 时间变化量</td></tr><tr><td><strong>User time</strong></td><td>用户模式下的 CPU 时间</td></tr><tr><td><strong>User delta</strong></td><td>用户模式下的 CPU 时间变化量</td></tr><tr><td><strong>Total time</strong></td><td>总的 CPU 时间</td></tr><tr><td><strong>Total delta</strong></td><td>总的 CPU 时间变化量</td></tr><tr><td><strong>Priority</strong></td><td>CPU 优先级</td></tr></tbody></table>

特别地：

1.  CPU 周期数
    1.  指 CPU 时钟信号的周期数，即 CPU 在某段时间内进行的时钟脉冲数。
    2.  CPU 周期代表一次时钟脉冲，CPU 在每个时钟周期内可以执行一部分指令（例如，取指令、解码、执行、写回等）。
    3.  在性能分析中，较高的 CPU 周期数可能表示 CPU 正在执行大量的计算任务，而较低的周期数则可能表示 CPU 处于空闲状态或工作负载较轻

# 内存部分

<table><tbody><tr><td>字段</td><td>解释</td></tr><tr><td>Private bytes</td><td>该进程私有的内存量，即该进程独占使用的内存，不与其他进程共享</td></tr><tr><td>Private bytes delta</td><td>自上次采样以来，该进程私有字节数的变化量</td></tr><tr><td>Peak private bytes</td><td>该进程自启动以来，私有字节的峰值</td></tr><tr><td>Virtual size</td><td>该进程已分配的虚拟内存总量</td></tr><tr><td>Peak virtual size</td><td>该进程自启动以来，虚拟内存的峰值</td></tr><tr><td>Page faults</td><td>该进程自启动以来发生的页错误总次数</td></tr><tr><td>Page faults delta</td><td>自上次采样以来发生的页错误数变化量</td></tr><tr><td>Hard faults</td><td>该进程自启动以来发生的硬页错误总次数</td></tr><tr><td>Hard faults delta</td><td>自上次采样以来发生的硬页错误数变化量</td></tr><tr><td>Working set</td><td>当前在物理内存中驻留的该进程的内存量</td></tr><tr><td>Peak working set</td><td>该进程自启动以来，工作集的峰值</td></tr><tr><td>Private WS</td><td>当前在物理内存中驻留的该进程私有的工作集内存量</td></tr><tr><td>Shareable WS</td><td>当前在物理内存中驻留的可共享的工作集内存量</td></tr><tr><td>Shared WS</td><td>当前在物理内存中驻留的已共享的工作集内存量</td></tr><tr><td>Paged pool bytes</td><td>该进程使用的分页池内存量</td></tr><tr><td>Peak paged pool bytes</td><td>该进程自启动以来，分页池内存的峰值</td></tr><tr><td>Nonpaged pool bytes</td><td>该进程使用的非分页池内存量</td></tr><tr><td>Peak nonpaged pool bytes</td><td>该进程自启动以来，非分页池内存的峰值</td></tr><tr><td>Shared commit</td><td>当前在物理内存中驻留的已提交的共享内存量</td></tr><tr><td>Private commit</td><td>当前在物理内存中驻留的已提交的私有内存量</td></tr><tr><td>Peak private commit</td><td>该进程自启动以来，私有提交内存的峰值</td></tr><tr><td>Page priority</td><td>该进程的页面优先级</td></tr></tbody></table>

特别地：

1.  Page faults 和 Hard faults：
    1.  Page faults 包含 Soft Page Fault 和 Hard Page Fault
    2.  Hard Page Fault 是指在应用程序尝试访问一个不在物理内存中的内存页面时发生的页错误。此错误会触发磁盘 I/O。
    3.  Soft Page Fault 是指在应用程序尝试访问一个不在当前工作集中，但在物理内存中的页面的时候的也错误。此错误不会触发磁盘 I/O，只会更新页面表。

# I/O 部分

<table><tbody><tr><td><strong>字段</strong></td><td><strong>解释</strong></td></tr><tr><td><strong>Reads</strong></td><td>读取操作的次数</td></tr><tr><td><strong>Reads delta</strong></td><td>读取操作次数的变化量</td></tr><tr><td><strong>Read bytes</strong></td><td>读取的字节数</td></tr><tr><td><strong>Read bytes delta</strong></td><td>读取字节数的变化量</td></tr><tr><td><strong>Writes</strong></td><td>写入操作的次数</td></tr><tr><td><strong>Writes delta</strong></td><td>写入操作次数的变化量</td></tr><tr><td><strong>Write bytes</strong></td><td>写入的字节数</td></tr><tr><td><strong>Write bytes delta</strong></td><td>写入字节数的变化量</td></tr><tr><td><strong>Other</strong></td><td>其他 I/O 操作的次数（如控制命令）</td></tr><tr><td><strong>Other delta</strong></td><td>其他 I/O 操作次数的变化量</td></tr><tr><td><strong>Other bytes</strong></td><td>其他 I/O 操作的字节数</td></tr><tr><td><strong>Other bytes delta</strong></td><td>其他 I/O 操作字节数的变化量</td></tr><tr><td><strong>Total bytes</strong></td><td>总的 I/O 操作字节数</td></tr><tr><td><strong>Total bytes delta</strong></td><td>总的 I/O 操作字节数的变化量</td></tr><tr><td><strong>Total bytes (average)</strong></td><td>平均 I/O 操作字节数</td></tr><tr><td><strong>I/O priority</strong></td><td>I/O 操作的优先级</td></tr></tbody></table>

IO 主要分 `磁盘 I/O` 和 `网络 I/O`

在`网络 I/O` 中可能用 Receives 和 Sends 来表示 读写。

# GPU 部分

<table><tbody><tr><td><strong>字段</strong></td><td><strong>解释</strong></td></tr><tr><td><strong>Dedicated memory</strong></td><td>GPU 专用内存的使用量</td></tr><tr><td><strong>Shared memory</strong></td><td>GPU 共享内存的使用量</td></tr><tr><td><strong>Commit memory</strong></td><td>提交给 GPU 使用的内存量</td></tr><tr><td><strong>Total memory</strong></td><td>GPU 使用的总内存量</td></tr></tbody></table>

# 其他

<table><tbody><tr><td><strong>字段</strong></td><td><strong>解释</strong></td></tr><tr><td><strong>Handles</strong></td><td>当前进程打开的句柄数</td></tr><tr><td><strong>Peak handles</strong></td><td>当前进程在其生命周期中打开的最大句柄数</td></tr><tr><td><strong>GDI handles</strong></td><td>图形设备接口（GDI）对象的句柄数</td></tr><tr><td><strong>Peak GDI handles</strong></td><td>图形设备接口（GDI）对象的最大句柄数</td></tr><tr><td><strong>USER handles</strong></td><td>用户对象（如窗口、菜单等）的句柄数</td></tr><tr><td><strong>Peak USER handles</strong></td><td>用户对象的最大句柄数</td></tr><tr><td><strong>Running time</strong></td><td>进程的总运行时间</td></tr><tr><td><strong>Suspended time</strong></td><td>进程的暂停时间</td></tr><tr><td><strong>Hang count</strong></td><td>进程挂起的次数</td></tr><tr><td><strong>Ghost count</strong></td><td>进程成为幽灵进程的次数</td></tr><tr><td><strong>NetworkTxRxBytes</strong></td><td>网络传输和接收的字节数</td></tr></tbody></table>', 'win', NULL, 'published', 0, 1386, 5, 141, 1716923880, 1716923880, 1736417068);
INSERT INTO posts (slug, title, excerpt, body, tag_id, series, status, pinned, words, read_time, views, published_at, created_at, updated_at) VALUES ('how-to-enum-process-in-windows', 'Windows 中遍历进程', '这篇文章介绍了在Windows中遍历进程的四种方法：
1. EnumProcesses：常用且简单，但只返回进程ID，需获取进程句柄以获得更多信息。
2. CreateToolhelp32Snapshot：提供详细信息（ID、线程等），但内存占用大且速度最慢。
3. NtQuerySystemInformation：速度快且详细，但需大缓冲区，内存占用高。
4. NtGetNextProcess：', '# 背景

Windows 中经常遇到需要遍历所有进程的诉求，Windows 中有多种方式可以遍历进程。

下面将对常规和不常规的方式做一个汇总。

# 效果

先看对比效果：

如下图是四个方式遍历一次当前所有进程所花费的时长。可以看到 native 的速度遥遥领先。

![](https://media.frendguo.com/2024/09/image-98.png)

那接下来就看看，这几种方式是怎么做的。

# 方法一：`EnumProcesses`

[EnumProcesses](https://learn.microsoft.com/en-us/windows/win32/api/psapi/nf-psapi-enumprocesses) 是最常用到的，也是最直接的方式了。

## 示例

```
DWORD aProcesses[1024] = { 0 }, cbNeeded, cProcesses;
EnumProcesses(aProcesses, sizeof(aProcesses), &cbNeeded);
```

## 注意

-   EnumProcesses 使用中，无法提前预测当前系统中存在多少个进程，所以通常采取一个大数组的方式来获取。
-   如果想获取总共多少个进程，可以通过 `cbNeeded/sizeof(DWORD)` 来获取。
-   如果 `cbNeeded/sizeof(DWORD)` 与数组大小一致，可能是因为缓冲区不够，建议将缓冲区增大后再次枚举
-   只包含进程ID，如果要获取其他信息，需要先通过 `OpenProcess` 获取进程句柄来获取
-   枚举速度中偏上

# 方法二：`CreateToolhelp32Snapshot`

还有一种常见的方式，就是通过 `CreateToolhelp32Snapshot` 拍快照，再通过 `Process32Next` 来枚举进程的方式。

## 示例

```
void EnumProcessBySnap(std::vector<DWORD>& pids) {
    HANDLE hProcessSnap = CreateToolhelp32Snapshot(TH32CS_SNAPPROCESS, 0);
    if (hProcessSnap == INVALID_HANDLE_VALUE) {
        std::cerr << "CreateToolhelp32Snapshot (of processes) failed: " << GetLastError() << std::endl;
        return;
    }

    PROCESSENTRY32 pe32;
    pe32.dwSize = sizeof(PROCESSENTRY32);

    // Retrieve information about the first process
    if (!Process32First(hProcessSnap, &pe32)) {
        std::cerr << "Process32First failed: " << GetLastError() << std::endl; // show cause of failure
        CloseHandle(hProcessSnap);          // clean the snapshot object
        return;
    }

    do
    {
        pids.push_back(pe32.th32ProcessID);
    } while (Process32Next(hProcessSnap, &pe32));
}
```

## 注意

-   快照中除了包含进程ID，还包含线程、父进程和优先级信息，所以占用的内存会相对比较大。需要结合自己的诉求
-   枚举速度最慢
-   占用的内存最大

# 方法三：`NtQuerySystemInformation`

通过 `NtQuerySystemInformation` + `**SystemProcessInformation**` 可以获取到包含 `**SYSTEM_PROCESS_INFORMATION**` 结构的数组。

## 示例

```
void EnumProcessByQueryInformation(std::vector<DWORD>& pids) {
    DWORD   dwSize = 0xFFFFF;
    LPTSTR pBuf = new TCHAR[dwSize];
    PSYSTEM_PROCESS_INFORMATION pInfo = { 0 };

    pInfo = (PSYSTEM_PROCESS_INFORMATION)pBuf;
    auto status = NtQuerySystemInformation(SystemProcessInformation, pInfo, dwSize, &dwSize);
    if (!NT_SUCCESS(status)) {
        std::cerr << "NtQuerySystemInformation failed: " << status << std::endl;
        return;
    }

    while (pInfo->NextEntryOffset)
    {
        pids.push_back(HandleToULong(pInfo->UniqueProcessId));

        pInfo = (PSYSTEM_PROCESS_INFORMATION)(((PUCHAR)pInfo) + pInfo->NextEntryOffset);
    }
}
```

## 注意

-   跟 `EnumProcesses` 一样，缓冲区需要采用大数组来存储，缓冲区不够的时候，会报错
-   包含的信息较多，具体看 `SYSTEM_PROCESS_INFORMATION` 结构
-   由于其调用链较短，在获取足够数据的情况下，速度较快
-   占用内存较多

# 方法四：`NtGetNextProcess`

此方式是一个导出但未文档化的接口，可以从 或者 [phnt](https://github.com/winsiderss/phnt) 中找到对应的接口。

## 示例

```
void EnumProcess(std::vector<DWORD>& pids) {
    HANDLE hProcess = nullptr;
    HANDLE nextProcess = NULL;
    while (NT_SUCCESS(NtGetNextProcess(hProcess, PROCESS_QUERY_INFORMATION, 0, 0, &nextProcess))) {
        auto pid = GetProcessId(nextProcess);
        pids.push_back(pid);
        hProcess = nextProcess;
    }
}
```

## 注意

-   使用此方式，请确保与运行的系统是兼容的。可以看对应版本的 ntoskrnl.exe 有无导出此接口
-   其返回的进程句柄，可以用来获取你想要的信息
-   此方法直接读取内核对象的链表，所以跟用户态拿到的进程列表存在出入。0（System Idle Process）、4（System）、332（Secure system）、374（Registry）等进程无法获取，还有部分进程内核进程对象存在，但用户态进程不一定存在，需要额外进行处理。请谨慎使用。
-   获取速度最快（比其他方式快了近10倍）

# 总结

不同的方式可以适应不同的诉求，各有利弊，需要了解详细后再选择使用。', 'win', NULL, 'published', 0, 936, 3, 344, 1717387260, 1717387260, 1728890563);
INSERT INTO posts (slug, title, excerpt, body, tag_id, series, status, pinned, words, read_time, views, published_at, created_at, updated_at) VALUES ('how-to-disable-or-enable-startup-app-in-taskmgr', 'Windows 任务管理器是怎么启用/禁用应用自启动的', '任务管理器如何启用或禁用开机自启动项？让我们逐步分析，通过一些工具帮你更好地理解系统功能的实现。具体来说，你可以通过编辑注册表项来控制应用的启动状态，并借助工具如 Process Monitor 和 IDA Pro，深入分析这些系统操作背后的逻辑和实现过程。', '不想看分析过程的，可以直接跳转到最后的汇总。

# 背景

通常我们要增加一个自启动，会在 `SOFTWARE\Microsoft\Windows\CurrentVersion\Run` 中添加一个项。如果需要禁用，很正常的思路是从次注册表中移除，然后保存到另外一个地方，待下次启动后，再把这一项添加回来（`autoruns` 就是这么干的）

但这样会有个问题，当被禁用（从注册表中移除）后，就相当于又被移除出去了，这样在任务管理器中就无法看到这个应用，而不是显示此应用被禁用。

看了下任务管理器是怎么做的，发现其并没有移除原注册表项，也实现了禁用的效果。

接下来就来研究下它是怎么实现的。

# 分析

开始上工具分析：

首先我们先用 Process Monitor 来看看禁用/启用自启动项的时候，任务管理器干了啥。

## Process Monitor 初步分析

Process Monitor 可以在 [https://live.sysinternals.com/](https://live.sysinternals.com/) 中下载到。

打开 Process Monitor，并在过滤器中选择【Process Name】，并选择【taskmgr.exe】，如下图所示：

![](https://media.frendguo.com/2024/09/image-99.png)

然后我们就可以在任务管理器上禁止一个应用，然后马上停止收集。这里以向日葵（SunloginClient.exe）为例。就可以看到如下的信息：

![](https://media.frendguo.com/2024/09/image-100-1024x444.png)

我们可以关注到`HKLMSOFTWAREMicrosoftWindowsCurrentVersionExplorerStartupApprovedRunSunloginClient` 这个注册表项。

再开启、禁用。发现此项确实有被修改。

## 注册表项值

从 Process Monitor 和 Regedit 中我们可以看到，这个项是一个二进制的值。这就有点麻烦了。

我们分别收集启用和禁用情况下的值：

启用时：

![](https://media.frendguo.com/2024/09/image-101.png)

禁用时：

![](https://media.frendguo.com/2024/09/image-102.png)

很明显，我们还是没法知道这些值都代表什么意思。

于是，用上我们的搜索大法：

发现一个相对比较有用的回答：

![](https://media.frendguo.com/2024/09/image-103-1024x716.png)

链接：

到这里，我们其实只了解了前两位的值有什么用。但后面的值，是没有信息的。

于是，我们就需要用逆向的手段来做进一步的分析了。

主要可以从静态分析和动态分析来入手。这里以静态分析为例：

### IDA Pro

静态分析上，我们可以通过 ida pro 来进行分析。

首先我们需要找到突破口，根据之前的注册表，尝试搜索【`StartupApproved`】，如下图：

![](https://media.frendguo.com/2024/09/image-104.png)

于是就搜到了 ，跳转到那块区域：

![](https://media.frendguo.com/2024/09/image-105-1024x154.png)

![](https://media.frendguo.com/2024/09/image-106-1024x306.png)

从上图中，我们可以看到，其被引用在 `StartupDB::StartupApproval::Initialize` ，微软居然还提供了 pdb，太棒了。

于是我们就可以在函数界面，搜索下 `StartupDB::StartupApproval` 相关的方法了。

![](https://media.frendguo.com/2024/09/image-107.png)

可以看到，里面包含 `SetBlockedItemInfo` 和 `GetBlockedItemInfo` 。点进去看看：

以 `SetBlockedItemInfo` 为例，可以看到，基本没啥逻辑，就是写了一下注册表。

![](https://media.frendguo.com/2024/09/image-108-1024x410.png)

于是，接下来找到调用它的人。通过 xref 可以看到，主要就是 `WdcStartupMonitor::DisableItem` 和 `WdcStartupMonitor::EnableItem` 。跳转到 `WdcStartupMonitor::DisableItem`。

因为我们主要看看其逻辑，所以我们直接看伪代码即可。按 F5 转到 伪代码界面（当然，这里也是可以将汇编代码发给 Chatgpt，让它帮忙解释下是什么意思。也很好）

由于代码比较多，这里我们看看重点代码：

![](https://media.frendguo.com/2024/09/image-109-1024x698.png)

从代码中可以看到：

`SystemTimeAsFileTime` 主要分两部分：

1.  `SystemTimeAsFileTime[0]` ：低 32 位就是上述提到的低两位（上述，02 为开启，03 为禁用）
2.  `SystemTimeAsFileTime[1]` ：高 64 位是 FileTime，也就是当前的系统时间

总共 12 位，也可以通过 `SetBlockedItemInfo` 的伪代码来验证。

![](https://media.frendguo.com/2024/09/image-111.png)

于是，我们基本搞清楚了注册表中的信息是什么。

# 验证

参考代码如下：

```
Zeus::WinRegistry reg(item->rootKey, item->regPath, false);

TaskmgrAutorunsRegData data;
std::vector<char> val;

try
{
    if (isEnable && !IsEnableType(item->type)) {
        data.type = item->type - 1;
        memset(&data.fileTime, 0, sizeof(FILETIME));
    } else if (!isEnable && IsEnableType(item->type) ) {
        data.type = item->type | 1;
        GetSystemTimeAsFileTime(&data.fileTime);
    }
    else {
        return true;
    }

    char* charData = reinterpret_cast<char*>(&data);

    for (int i = 0; i < sizeof(TaskmgrAutorunsRegData); i++) {
        val.push_back(charData[i]);
    }
    reg.SetBinary(item->name, val);

    return true;
}

// TaskmgrAutorunsRegData 定义
struct TaskmgrAutorunsRegData {
    // 01-禁用启动，具有管理员权限的用户可以启用
    // 02-已启用启动，具有管理员权限的用户可以禁用
    // 08-已启用启动，用户无法禁用(灰色显示)
    // 09-禁用启动，用户无法启用(灰色显示)
    int32_t type;
    FILETIME fileTime;
};
```

修改 SunloginClient.exe 的自启动后，可以通过任务管理器查看到禁用时间。

![](https://media.frendguo.com/2024/09/image-112-1024x529.png)

重启后，也不会自己启动。

于是，我们就达成目的了。

# 汇总

## 获取自启动列表

主要在如下注册表中枚举：

-   `"SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\StartupApproved\Run”`
-   `"SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\StartupApproved\Run32”`
-   `"SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\StartupApproved\StartupFolder”`

包含 `HKEY_LOCAL_MACHINE` 和 `HKEY_CURRENT_USER` 两个。

## 判断特定项是否开启自启动

获取 `TaskmgrAutorunsRegData` 的 type 是 2 或者是 8

## 设置特定项目的自启动状态

```
Zeus::WinRegistry reg(item->rootKey, item->regPath, false);

TaskmgrAutorunsRegData data;
std::vector<char> val;

try
{
    if (isEnable && !IsEnableType(item->type)) {
        data.type = item->type - 1;
        memset(&data.fileTime, 0, sizeof(FILETIME));
    } else if (!isEnable && IsEnableType(item->type) ) {
        data.type = item->type | 1;
        GetSystemTimeAsFileTime(&data.fileTime);
    }
    else {
        return true;
    }

    char* charData = reinterpret_cast<char*>(&data);

    for (int i = 0; i < sizeof(TaskmgrAutorunsRegData); i++) {
        val.push_back(charData[i]);
    }
    reg.SetBinary(item->name, val);

    return true;
}

// TaskmgrAutorunsRegData 定义
struct TaskmgrAutorunsRegData {
    // 01-禁用启动，具有管理员权限的用户可以启用
    // 02-已启用启动，具有管理员权限的用户可以禁用
    // 08-已启用启动，用户无法禁用(灰色显示)
    // 09-禁用启动，用户无法启用(灰色显示)
    int32_t type;
    FILETIME fileTime;
};
```

# 后续

后续研究还有几个方向：

1.  这里只分析了注册表的自启动应用，还有 UWP 应用，怎么枚举，怎么设置？
2.  这里只分析了，基于注册表有值的情况下的修改。系统是怎么判断什么时候是 2，什么时候是 8，以及是否还有其他类型？', 'win', NULL, 'published', 0, 1575, 6, 431, 1724803800, 1724803800, 1728890567);
INSERT INTO posts (slug, title, excerpt, body, tag_id, series, status, pinned, words, read_time, views, published_at, created_at, updated_at) VALUES ('remote-desktop-with-sign-in-microsft-accout', '如何通过微软账号登录远程桌面', '引入 现在越来越多人通过微软账户来登录 Windows 了，在用微软的远程桌面（也就是 mstsc.exe ）的时候，就会发现，不管是输入 pin 码还是在线账户的密码都无法登录成功。 方法一 执行后，会提示你输入微软账号的密码，输入后，回车就好了。 当出现下图的提示时，表示校验成功了。 注意：输入密码的时候是不会显示', '# 引入

现在越来越多人通过微软账户来登录 Windows 了，在用微软的远程桌面（也就是 `mstsc.exe`）的时候，就会发现，不管是输入 pin 码还是在线账户的密码都无法登录成功。

# 方法一

```
runas /u:MicrosoftAccount\username@example.com winver
```

执行后，会提示你输入微软账号的密码，输入后，回车就好了。

当出现下图的提示时，表示校验成功了。

![](https://media.frendguo.com/2024/10/image.png)

注意：输入密码的时候是不会显示的。

> 这个命令会尝试使用在线账户去执行 winver 的命令，最重要的是，他会在后台缓存你的密码。这样当远程桌面连接的时候，就可以使用这个密码去校验了。

## 对于无密码账户

如果你开启了微软账号的【无密码登录（Passwordless accout）】功能，请在 [https://account.live.com/proofs/manage/additional](https://account.live.com/proofs/manage/additional) 关闭它并添加一个密码。

![](https://media.frendguo.com/2024/10/image-1-1024x253.png)

# 方法二：创建一个本地账户链接

这种方法本质就是，给在线账户关联一个本地账户，然后通过本地账户的密码来进行登录。

操作如下：

1.  进入设置 → 账户 → 你的信息，点击使用本地账户登录

![](https://media.frendguo.com/2024/10/image-2-1024x177.png)

1.  完成后，重新启动计算机，验证是否可以使用刚刚设置的本地账户用户名/密码从另一台计算机进行连接。
2.  【可选】返回到第一步，点击“使用 Microsoft 账户登录”，将账户和在线账户重新连接

这样操作之后，我们就可以愉快的使用在线账户登录远程桌面了。', 'win', NULL, 'published', 0, 452, 2, 1449, 1728846240, 1728846240, 1728893654);
