INSERT INTO posts (slug, title, excerpt, body, tag_id, series, status, pinned, words, read_time, views, published_at, created_at, updated_at) VALUES ('real-time-monitor-etw-event-id-in-cpp', '如何通过 C++ 实时监听 ETW 事件', '引入 ETW（Event Tracing for Windows）是 Windows 平台上非常强大的事件跟踪机制，广泛用于调试、性能分析以及日志记录等场景。相较于传统的日志方式，ETW 在内核态和用户态都有提供良好的事件跟踪接口，可以帮助开发者更灵活地收集关键信息。 在许多应用场景下，我们不仅要监听某个 Provid', '# 引入

ETW（Event Tracing for Windows）是 Windows 平台上非常强大的事件跟踪机制，广泛用于调试、性能分析以及日志记录等场景。相较于传统的日志方式，ETW 在内核态和用户态都有提供良好的事件跟踪接口，可以帮助开发者更灵活地收集关键信息。

在许多应用场景下，我们不仅要监听某个 Provider（事件提供者）产生的所有事件，还需要进一步通过 Event ID 或关键字（Keyword）等进行过滤。ETW 本身提供了非常高效的内核态过滤功能，可以在事件触发时就直接按需过滤，减少数据传输和处理的开销。

# 步骤

以下是实现实时监听并根据 Event ID 进行过滤的核心步骤解析。

## 1\. 启动 ETW Session

-   **`EVENT_TRACE_PROPERTIES` 结构**  
    这是配置 ETW 会话属性的核心结构，除了常用的缓冲区大小、标记位（`WNODE_FLAG_TRACED_GUID`）等，还需要指定 `LogFileMode` 为 `EVENT_TRACE_REAL_TIME_MODE`，才能开启实时模式。
-   **`StartTrace`**  
    通过 `StartTrace` 来启动一个新的 ETW Session，并返回一个 `TRACEHANDLE` 会话句柄。在调用时，我们需要将 `EVENT_TRACE_PROPERTIES` 与会话名称一起传入。

```
ULONG status = StartTrace(&hSession, sessionName, pSessionProperties);
```

## 2\. 配置内核态过滤器（EVENT\_FILTER\_EVENT\_ID）

-   **`EVENT_FILTER_EVENT_ID` 结构**  
    这是一个用于表明我们想要捕获（或排除）哪些事件 ID 的结构。其主要成员包括：
    -   `FilterIn`：`TRUE` 表示“包含”指定的事件 ID；若为 `FALSE`，则表示排除。
    -   `Count`：要过滤的事件 ID 个数。
    -   `Events`：指向实际的事件 ID 数组。
-   **`EVENT_FILTER_DESCRIPTOR`**  
    这个结构用于向 ETW API 传递过滤器的元信息，它包括指向过滤器数据的指针、数据大小以及过滤器的类型。  
    此处我们将 `Type` 设置为 `EVENT_FILTER_TYPE_EVENT_ID`，表示按事件 ID 进行过滤。
-   **`ENABLE_TRACE_PARAMETERS`**  
    在调用 `EnableTraceEx2` 时，需要通过该结构把过滤器数组传进去（实际上可以传入多个过滤器）。  
    我们在示例中只用到一个过滤器，因此 `FilterDescCount = 1`。

## 3\. 启用 Provider 并应用过滤规则

-   **`EnableTraceEx2`**  
    该函数是新的、较灵活的 Provider 启用接口。相比 `EnableTrace`，它支持传入更多参数，比如过滤描述符。  
    其中比较关键的参数有：
    -   `EVENT_CONTROL_CODE_ENABLE_PROVIDER`：表示启用 Provider。
    -   `TRACE_LEVEL_VERBOSE`：设置事件级别为最高级别。
    -   `MatchAnyKeyword = 0xFFFFFFFF` 和 `MatchAllKeyword = 0`：如果对关键字无特殊需求，可以这样表示“不限制”。
    -   `enableParams`：我们前面构造好的过滤参数。

```
status = EnableTraceEx2(
    hSession,
    &providerGuid,
    EVENT_CONTROL_CODE_ENABLE_PROVIDER,
    TRACE_LEVEL_VERBOSE,
    0xFFFFFFFF,
    0,
    0,
    &enableParams
);
```

## 4\. 打开 Trace 并实时消费事件

-   **`OpenTrace`**  
    打开指定会话的 Trace，用于后续调用 `ProcessTrace` 读取事件数据。  
    我们通过设置 `logFile.ProcessTraceMode = PROCESS_TRACE_MODE_REAL_TIME | PROCESS_TRACE_MODE_EVENT_RECORD` 来指定实时模式和 `EventRecord` 回调类型。
-   **`ProcessTrace`**  
    开始循环接收事件，直到会话停止或遇到其他终止条件。  
    在循环过程中，每个新到的事件都会调用我们在 `logFile.EventRecordCallback` 中指定的回调函

```
EVENT_TRACE_LOGFILEW logFile = {};
logFile.LoggerName          = (LPWSTR)sessionName; 
logFile.ProcessTraceMode    = PROCESS_TRACE_MODE_REAL_TIME 
                            | PROCESS_TRACE_MODE_EVENT_RECORD;
logFile.EventRecordCallback = (PEVENT_RECORD_CALLBACK)EventRecordCallback;
```

## 5\. 回调函数：`EventRecordCallback`

该函数的签名固定，入参是 `PEVENT_RECORD`。通过 `EventRecord->EventHeader.EventDescriptor`，可以拿到事件的 ID、Level 等信息（在内核态已经过滤了指定 ID，因此进入回调的事件一定符合过滤条件）。

若需要进一步获取其他字段（如自定义字段、Payload 数据等），可以使用以下 TDH（Tracing Data Helper）API：

-   `TdhGetEventInformation()`：获取事件元数据。
-   `TdhFormatProperty()`：获取并格式化指定属性。

## 6\. 停止会话 & 资源清理

在不再需要监听时，通过 `ControlTrace` 并指定 `EVENT_TRACE_CONTROL_STOP` 来停止会话。随后可以调用 `CloseTrace` 关闭之前打开的 Trace。最后释放掉分配的内存等资源。

# 常见问题与注意事项

1.  **权限问题**  
    启动 ETW Session 需要管理员权限，建议在“以管理员身份”运行时执行，否则可能会返回权限不足的错误。
2.  **重复启动会话**  
    当会话名相同且已存在时，`StartTrace` 可能会失败或返回特定错误，需注意清理或改名。
3.  **过滤规则的上限**  
    不同版本的 Windows 对过滤器支持可能略有差异，如果需要更复杂的过滤（例如同时根据多个关键字和事件级别过滤），需要仔细阅读相关文档，并在 `ENABLE_TRACE_PARAMETERS` 中传入更多过滤描述符。
4.  **实时模式下的负载**  
    如果流量巨大，实时模式可能会消耗较多 CPU 和内存。实际生产环境中要结合性能需求，必要时采用文件日志或分段模式进行持久化。
5.  **回调函数中的处理**  
    在回调函数中尽量保证轻量级的操作，因为它是由系统在内部线程中同步回调。如果回调过于耗时，可能会导致事件堆积或丢失。

# 完整代码

```
#include <windows.h>
#include <evntrace.h>
#include <tdh.h>         // 包含 TdhGetEventInformation 等
#include <iostream>
#include <string>

#pragma comment(lib, "tdh.lib")
#pragma comment(lib, "advapi32.lib")
#pragma comment(lib, "ole32.lib")

//---------------------------------------------------------------------------
// 全局回调，用于处理已通过内核态过滤后的事件
//---------------------------------------------------------------------------
static VOID WINAPI EventRecordCallback(PEVENT_RECORD pEventRecord)
{
    // 这里的事件一定是 Event ID = 100 或 200（因为已在内核态过滤）
    USHORT eventId = pEventRecord->EventHeader.EventDescriptor.Id;
    std::wcout << L"Received ETW event, ID = " << eventId << L"
";

    // 如果需要获取更多字段，可使用 TdhGetEventInformation()、TdhFormatProperty() 等
}

//---------------------------------------------------------------------------
// BufferCallback：可选，用于监测缓冲区情况，一般直接返回 TRUE
//---------------------------------------------------------------------------
static ULONG WINAPI BufferCallback(EVENT_TRACE_LOGFILEW* /*pLogFile*/)
{
    return TRUE; // 返回 TRUE 继续处理
}

//---------------------------------------------------------------------------
// 主函数
//---------------------------------------------------------------------------
int wmain()
{
    //------------------------------------------------------------------------
    // 0. Provider GUID & Event ID
    //------------------------------------------------------------------------
    // 目标 Provider 的 GUID: {cfc18ec0-96b1-4eba-961b-622caee05b0a}
    GUID providerGuid = 
    { 0xcfc18ec0, 0x96b1, 0x4eba, {0x96, 0x1b, 0x62, 0x2c, 0xae, 0xe0, 0x5b, 0x0a} };

    // 只想捕获的事件 ID 列表
    USHORT desiredEvents[] = { 100, 200 };

    //------------------------------------------------------------------------
    // 1. 准备并启动 ETW Session（实时模式）
    //------------------------------------------------------------------------
    // 1.1 分配 EVENT_TRACE_PROPERTIES
    size_t bufferSize = sizeof(EVENT_TRACE_PROPERTIES) + 2 * MAX_PATH * sizeof(WCHAR);
    EVENT_TRACE_PROPERTIES* pSessionProperties = 
        (EVENT_TRACE_PROPERTIES*)malloc(bufferSize);
    if (!pSessionProperties)
    {
        std::wcerr << L"Failed to allocate memory for session properties.
";
        return 1;
    }
    ZeroMemory(pSessionProperties, bufferSize);

    pSessionProperties->Wnode.BufferSize = (ULONG)bufferSize;
    pSessionProperties->Wnode.Flags      = WNODE_FLAG_TRACED_GUID;
    pSessionProperties->LogFileMode      = EVENT_TRACE_REAL_TIME_MODE;
    pSessionProperties->LoggerNameOffset = sizeof(EVENT_TRACE_PROPERTIES);

    LPCWSTR sessionName = L"MyCppEtwSession";
    TRACEHANDLE hSession = 0;

    // 1.2 调用 StartTrace
    ULONG status = StartTrace(&hSession, sessionName, pSessionProperties);
    if (status != ERROR_SUCCESS)
    {
        std::wcerr << L"StartTrace failed, error: " << status << L"
";
        free(pSessionProperties);
        return 1;
    }

    //------------------------------------------------------------------------
    // 2. 准备用于 “内核态” 过滤 Event ID 的数据结构
    //    关键在 EnableTraceEx2 + EVENT_FILTER_DESCRIPTOR
    //------------------------------------------------------------------------
    // 2.1 填充 EVENT_FILTER_EVENT_ID 结构（声明捕获的 Event ID 列表）
    EVENT_FILTER_EVENT_ID eventIdFilter = {};
    eventIdFilter.FilterIn = TRUE; // TRUE 表示 "只" 捕获这些事件（而不是排除）
    eventIdFilter.Count    = (USHORT)_countof(desiredEvents);
    eventIdFilter.Events   = desiredEvents;

    // 2.2 包装成 EVENT_FILTER_DESCRIPTOR
    EVENT_FILTER_DESCRIPTOR filterDesc = {};
    ZeroMemory(&filterDesc, sizeof(filterDesc));

    // 计算大小：EVENT_FILTER_EVENT_ID 本身 + (Count-1)*sizeof(USHORT)
    filterDesc.Ptr  = (ULONG_PTR)&eventIdFilter;
    filterDesc.Size = sizeof(EVENT_FILTER_EVENT_ID) 
                    + (eventIdFilter.Count - 1) * sizeof(USHORT);
    filterDesc.Type = EVENT_FILTER_TYPE_EVENT_ID; // 按 Event ID 过滤

    // 2.3 构造 ENABLE_TRACE_PARAMETERS，用于 EnableTraceEx2
    ENABLE_TRACE_PARAMETERS enableParams;
    ZeroMemory(&enableParams, sizeof(enableParams));
    enableParams.Version          = ENABLE_TRACE_PARAMETERS_VERSION_2;
    enableParams.EnableProperty   = 0;      // 不需要特殊属性
    enableParams.ControlFlags     = 0;
    enableParams.SourceId         = 0;
    enableParams.FilterDescCount  = 1;      // 我们的过滤器个数
    enableParams.EnableFilterDesc = &filterDesc;

    //------------------------------------------------------------------------
    // 3. 调用 EnableTraceEx2，传入过滤规则
    //------------------------------------------------------------------------
    status = EnableTraceEx2(
        hSession,                      // 第一步 StartTrace 返回的会话句柄
        &providerGuid,                 // 要启用的 Provider
        EVENT_CONTROL_CODE_ENABLE_PROVIDER,
        TRACE_LEVEL_VERBOSE,           // 事件级别
        0xFFFFFFFF,                    // MatchAnyKeyword
        0,                             // MatchAllKeyword
        0,                             // 超时时间（0 表示默认）
        &enableParams                  // 我们的过滤参数
    );
    if (status != ERROR_SUCCESS)
    {
        std::wcerr << L"EnableTraceEx2 failed, error: " << status << L"
";
        goto Cleanup;
    }

    //------------------------------------------------------------------------
    // 4. OpenTrace + ProcessTrace（实时消费事件）
    //------------------------------------------------------------------------
    EVENT_TRACE_LOGFILEW logFile = {};
    logFile.LoggerName          = (LPWSTR)sessionName; 
    logFile.ProcessTraceMode    = PROCESS_TRACE_MODE_REAL_TIME 
                                | PROCESS_TRACE_MODE_EVENT_RECORD;
    logFile.EventRecordCallback = (PEVENT_RECORD_CALLBACK)EventRecordCallback;
    logFile.BufferCallback      = (PEVENT_TRACE_BUFFER_CALLBACKW)BufferCallback;

    TRACEHANDLE hTrace = OpenTraceW(&logFile);
    if (hTrace == INVALID_PROCESSTRACE_HANDLE)
    {
        std::wcerr << L"OpenTrace failed.
";
        goto Cleanup;
    }

    std::wcout << L"Start capturing ETW events (only EventID=100 or 200)...
";
    status = ProcessTrace(&hTrace, 1, NULL, NULL);
    if (status != ERROR_SUCCESS)
    {
        std::wcerr << L"ProcessTrace failed, error: " << status << L"
";
    }

    //------------------------------------------------------------------------
    // 5. 清理：停止会话 & 关闭 Trace
    //------------------------------------------------------------------------
    status = ControlTrace(hSession, sessionName, pSessionProperties, EVENT_TRACE_CONTROL_STOP);
    if (status != ERROR_SUCCESS)
    {
        std::wcerr << L"ControlTrace (Stop) failed, error: " << status << L"
";
    }
    CloseTrace(hTrace);

Cleanup:
    if (pSessionProperties)
    {
        free(pSessionProperties);
        pSessionProperties = nullptr;
    }
    std::wcout << L"ETW capturing finished.
";
    return 0;
}
```', 'win', NULL, 'published', 0, 2092, 7, 610, 1737514779, 1737514779, 1737514904);
INSERT INTO posts (slug, title, excerpt, body, tag_id, series, status, pinned, words, read_time, views, published_at, created_at, updated_at) VALUES ('how-to-loging-by-etw-provider', '如何通过 ETW Provider 来记录应用日志', '背景 最近在做一些性能优化的时候，发现很多应用经常会出现文件 I/O 爆高，但又没做啥事情。结果分析下来发现，都是在写日志。 于是就有了这么一篇，怎么利用 Windows 自己提供的 ETW 来记录应用日志。 通过 ETW 记录日志有什么好处 ETW（Event trace for Windows） 是 Windows', '# 背景

最近在做一些性能优化的时候，发现很多应用经常会出现文件 I/O 爆高，但又没做啥事情。结果分析下来发现，都是在写日志。

于是就有了这么一篇，怎么利用 Windows 自己提供的 ETW 来记录应用日志。

# 通过 ETW 记录日志有什么好处

ETW（Event trace for Windows） 是 Windows 提供的一种事件跟踪机制，可以用来记录应用程序的运行时事件。

ETW Provider 提供的日志相比文件日志，主要有以下优点：

-   方便扩展：日志采用结构化数据，方便第三方解析
-   高性能、低开销：采用内核缓冲区，批量写入磁盘
-   实时记录：支持实时事件流
-   隐私性：采用二进制日志 + 资源 dll/exe 的方式，在不具备资源 dll 的前提下，无法解析

# 怎么做

作为普通应用程序，没法直接使用微软的标准库来做，这里会相对麻烦一点。但通过微软提供的一些工具，可以稍微提升一定的效率。

我们采取基于清单的方式来创建 provider。

1.  创建清单文件
2.  打开 `ecmangen.exe`

我们可以通过 SDK 中自带的图形化工具（`ecmangen.exe`）来生成清单文件。

如果你安装了 8.1 的 SDK，你可以在 `C:\Program Files (x86)\Windows Kits\8.1\bin\x64\` 找到它。

如果你没安装，可以看下面这个：

打开它，会得到一个这样的应用：

![](https://media.frendguo.com/2025/01/6fffd0a2-3e87-4d6a-a731-c0b3d6951eb3.png)

然后就可以开始创建 provider 了。

2.  创建 Provider

选择【Events Section】部分，右击，选择【New】-【Provider】

根据提示，填写好 `Name`、`Symbol`、`GUID`（可以自动生成一个）、`Decoding file locations`（这个可以后面再进行修改的）

如下图所示：

![](https://media.frendguo.com/2025/01/dfc4b0d4-932a-4ba9-a18e-21c90b1230ec.png)

下一步，我们就要开始创建我们的 event 了。开始 Event 之前，我们需要先创建一些关键属性处理，以方便 Event 创建的时候进行选择。

3.  创建基础属性

关于基础属性，详细介绍可以看：[ETW：Windows 事件追踪](https://frendguo.com/event-trace-for-windows-101/)

这里，我们需要创建或修改的有：

-   `Channels`：主要用来区分不同权限的事件。比如 Admin 为管理员需要关注的事件；而 Debug 则是开发人员需要关注的事件
-   `Tasks`：主要用来对事件进行分类的。Tasks 主要针对不同的任务或者场景。这个需要结合业务来拆分
-   `Opcodes`：也是用来对事件进行分类的。Opcodes 主要针对的具体的行为。比如创建进程等
-   `Templates`：用于辅助事件显示结构化信息的关键属性。给与字段的解析和定义。比如，在场景激活这个事件中，我有这么一个 template：

![](https://media.frendguo.com/2025/01/28c5a215-d659-47e0-a6e3-fff64b999bca.png)

还有额外的一些属性可以按需使用。

4.  创建 Event

关键就是创建 Event 了，这是对日志的直接表达。

需要定义 Symbol、EventId、Event Version（主要用于版本管理）和一些基础属性，这个需要根据业务定义来。

如下是场景激活事件的事件详情，供参考。

![](https://media.frendguo.com/2025/01/f111dee0-322e-44c6-8216-e3240257fdab.png)

然后按需完成事件的增加。满足需求后，通过【File】-【Save/Save As】将 man 文件保存即可。

于是我们就得到了我们的 xxx.man 清单文件。

2.  创建日志宏

创建完清单文件，接下来就可以通过清单文件生成宏信息，在代码中调用更方便。

这里需要用到 `mc.exe`，可以通过 man 文件来生成 `.h`、`.rc`、`.bin`文件。

> mc.exe 是跟随 win10 的 SDK 带下来的。

```
frend in ~\Desktop	estt λ mc -um .\MyProvider.man
frend in ~\Desktop	estt λ ls

    Directory: C:\Users\frend\Desktop	estt

Mode                 LastWriteTime         Length Name
----                 -------------         ------ ----
-----           1/23/2025  4:28 PM            144 MSG00001.bin
-----           1/23/2025  4:28 PM          35741 MyProvider.h
-a---           12/5/2024 11:52 AM           4912 MyProvider.man
-----           1/23/2025  4:28 PM             77 MyProvider.rc
-----           1/23/2025  4:28 PM            970 MyProviderTEMP.BIN
```

于是，我们就可以创建 VS 项目，然后引入 .h 和 .rc 进行使用了。

3.  创建项目

这里需要把 .h 和 .rc 和 bin 文件加到项目中。

然后，就可以开始写代码了。.h 中有了较多的宏，所以写起来也非常的方便。

直接放代码：

```
#include <iostream>
#include <windows.h>
#include <evntprov.h>

#include "MyProvider.h"

REGHANDLE g_ProviderHandle = NULL;

int main()
{
    ULONG status = EventRegisterProviderDemo();
    if (status != ERROR_SUCCESS) {
        std::cout << "Failed to register ETW provider. Error: " << status << std::endl;
        return status;
    }

    // 写入事件
    while (true) {
        if (EventEnabledScene_Active()) {
            // 准备参数
            const wchar_t* sceneName = L"MainScene";
            ULONG processId = GetCurrentProcessId();

            EventWriteScene_Active(sceneName, processId);
        }

        std::cout << "Event written successfully!
";
        Sleep(1000);
    }

    // 程序结束前注销 provider
    EventUnregisterProviderDemo();

    return 0;
}
```

编译生成，即可将日志写到 ETW 中去了。

但这个时候，是没法看到这个 provider 和对应的 event 的。

> 这里建议将日志部分封装成一个 dll，将 bin 文件链接到 dll 中，用于解码 message

4.  安装清单文件

由于截至到目前为止，我们还没有安装清单文件，所以系统中是没法查到这个 provider 的，也就没法获取日志了。

安装清单文件可以用 `wevtutil`来安装。

```
wevtutil im .\MyProvider.man
```

安装完成后，就可以看到了。可以通过 `logman`来获取：

```
frend in ~\Desktop	estt λ logman query providers "providerDemo"

Provider                                 GUID
-------------------------------------------------------------------------------
ProviderDemo                             {16676E5F-DFC8-4A42-9F1E-14CF280F7AFD}

Value               Keyword              Description
-------------------------------------------------------------------------------
0x8000000000000000  Debug
0x4000000000000000  Admin

Value               Level                Description
-------------------------------------------------------------------------------
0x04                win:Informational    Information


The command completed successfully.
```

# 怎么查看日志

记录了日志，接下来就可以看看怎么获取日志了。

1.  实时观察

观察的话，可以通过 `Microsoft Message Analyzer` 实时观察。

如果在创建 provider 的时候，正确填写了 `Decoding file locations`，那应该直接在 `Microsoft Message Analyzer` 就可以看到了。

如果 dll/exe 存放的位置跟预定的 `Decoding file locations` 不一致，可以通过注册表来进行修改。

注册表地址：`HKEY_LOCAL_MACHINE\SOFTWARE\Microsoft\Windows\CurrentVersion\WINEVT\Publishers\<Provider GUID>`，例如：

![](https://media.frendguo.com/2025/01/bb005919-40ac-46ba-95b3-900b022b78c3.png)

2.  通过 C++ 获取

还可以通过接口来获取日志，这样方便编写日志工具来获取、分析日志。

具体怎么做可以看：[如何通过 C++ 实时监听 ETW 事件](https://frendguo.com/real-time-monitor-etw-event-id-in-cpp/)', 'win', NULL, 'published', 0, 1631, 6, 208, 1737682596, 1737682596, 1737682597);
INSERT INTO posts (slug, title, excerpt, body, tag_id, series, status, pinned, words, read_time, views, published_at, created_at, updated_at) VALUES ('wpa-wait-analysis-idle-time-in-windows', '【译】Wait Analysis - 寻找空闲时间', '原文：https://randomascii.wordpress.com/2012/05/05/xperf wait analysisfinding idle time/ Windows 性能工具包（Windows Performance Toolkit），也称为 xperf，是一个强大且免费的系统级别 Windows', '> 原文：[https://randomascii.wordpress.com/2012/05/05/xperf-wait-analysisfinding-idle-time/](https://randomascii.wordpress.com/2012/05/05/xperf-wait-analysisfinding-idle-time/)

Windows 性能工具包（Windows Performance Toolkit），也称为 [xperf](https://randomascii.wordpress.com/2015/09/24/etw-central/)，是一个强大且免费的系统级别 Windows 性能分析工具。在过去的文章中，我曾谈到使用 xperf 内置的采样分析器来定位 [PowerPoint 的性能瓶颈](https://randomascii.wordpress.com/2011/08/29/powerpoint-poor-performance-problem/)（其教程版本在[这里](https://randomascii.wordpress.com/2013/04/23/xperf-for-excess-cpu-consumption-wpa-edition/)），但这其实并没有完全展示出 xperf 的真正价值。尽管我认为 xperf 作为一个采样分析器要优于大多数替代方案（它的采样频率更高、开销更低，且能分析内核与用户模式），xperf 的真正强大之处在于它能揭示其他分析器根本无法测量的信息。

> 本文在 2015 年 9 月进行了更新，以兼容 WPA 10 和 UIforETW

简而言之，许多分析器可以告诉你「程序正在做什么」，但很少有分析器可以非常精准地告诉你「程序为什么什么都不做」。

更多关于此类调查的细节可参见这篇博文中提到的 [第二个 ETW 培训视频](https://randomascii.wordpress.com/2014/08/19/etw-training-videos-available-now/)。

---

## 故事背景

xperf 的学习曲线很陡峭。因此，我强烈建议你先阅读本系列之前的文章。最好的起点是 [ETW Central](https://randomascii.wordpress.com/2015/09/24/etw-central/)，其中提供了一个结构化良好的资源列表。

阅读完这些基础内容，并且在你安装了 UIforETW 并熟悉了部分 WPA 跟踪分析基础操作之后，就可以继续看这篇文章。

---

## Wait Analysis 的成功案例

我在使用 Wait Analysis 时，解决了许多性能问题。这其中的一些延迟虽然很短，不易察觉，但依然影响体验。另一些则是对使用产生了严重影响。而无论是哪一种，几乎都无法只用 CPU 采样或其他「常规」CPU 分析工具进行诊断。例如：

-   找到导致 Internet Explorer 和各种游戏启动时出现短暂卡顿的原因
-   分析 Luke Stackwalker（一个探查器）为什么在被使用时会导致游戏帧率出现抖动
-   发现某些情况下，从旧版 Windows 升级到新版后性能下降 10 倍的原因
-   查明为什么在使用 fraps 录制时会出现帧率卡顿
-   发现某些高负载系统中，一连串锁竞争导致帧率卡顿
-   发现并解决 Visual Studio 输出窗口反复出现 2~6 秒卡死的原因

最后这项调查就是我今天想重点讲述的。它足够简单且独立，可以在一篇（虽然有点长）的文章中完整地描述从头到尾的分析过程。

---

## 如何定位卡顿

![](https://randomascii.wordpress.com/wp-content/uploads/2015/09/image17.png)

要分析诸如帧率抖动或暂时性卡顿等瞬时问题，第一个挑战就是在跟踪数据（trace）中找到这段卡顿。因为一个跟踪可能覆盖了 60 秒的时间范围，而卡顿可能只持续 2 秒甚至更短，所以知道该在何处查看是至关重要的。下面是一些可行的方法：

-   通过对输入事件进行记录来查找触发卡顿的按键，因为输入事件通常和卡顿的出现时间紧密相关
-   在感兴趣的函数中使用自定义埋点（instrumentation）
-   观察 CPU 使用率或其他数据中是否有异常模式
-   从 *Window in Focus* 图表中寻找线索
-   利用操作系统本身的卡顿检测事件
-   记录下卡顿发生在「开始或停止」跟踪的相对时间位置

我自己就用过所有这些技巧。针对第一个方法，UIforETW 内置了一个[输入事件记录器](https://github.com/google/UIforETW/blob/master/UIforETW/KeyLoggerThread.cpp?ts=4)，它会将所有键盘和鼠标输入写入到跟踪文件里。如果你的卡顿恰好是在按下某个键或点击鼠标后触发的，那么通过查找该按键或鼠标事件就可以很容易地定位卡顿发生的时间点。

自定义埋点（即在程序的关键点发出 ETW 事件，例如在游戏中每帧或在执行某个慢操作时使用 [CETWScope](https://github.com/google/UIforETW/blob/master/include/ETWProviders/etwprof.h?ts=4)）也很常见。如果你可以给自己的游戏或应用加上埋点，出现问题时就能通过可视化事件很直观地看到「卡顿」或「延迟」究竟发生在哪里。不过，如果你要分析的是别人的程序，比如 Visual Studio，那就没法用这种方法。

有些时候，卡顿会显现在 CPU 使用率图表上。例如，我之前遇到的一个卡顿就因为 CPU 使用非常稳定，唯独中间出现了一个大缺口，一眼就能看出来。

*Window in Focus* 图表会追踪你切换窗口的情况，也能提供重要线索。

而一个能直接显示卡顿时间和时长的事件更是理想之选。其实在 Windows 7 及更新版本中，Win32k ETW 用户提供程序在检测到线程长时间没有处理消息、然后恢复时，就会发出相应事件。对于 Windows 7 及后续系统，这通常就够了，而 UIforETW [也默认启用](https://github.com/google/UIforETW/blob/master/UIforETW/UIforETWDlg.cpp?ts=4#L803)了这个提供程序。Vista 或者更早版本就没有这么方便了。

---

## 实践开始

我上传了一份示例跟踪文件（`2015-09-25_20-56-25 VS F8 short hang.zip`）到我的 [github bigfiles 仓库](https://github.com/randomascii/bigfiles/tree/master/ETWTraces)。如果你将这个 zip 文件下载并解压到 UIforETW 的跟踪目录（默认是 `Documents\\\\etwtraces`），然后在 UIforETW 中双击该文件，就可以用 WPA 10 打开它了。最好的学习方式就是跟我一起动手做。另外，你也应该下载同名的 .txt 文件，并将其复制到同一个 etwtraces 目录。这样当你在 UIforETW 中选中该跟踪文件时，UIforETW 会显示这个 .txt 文件的内容，你也可以在 *Trace information* 区域记录自己的分析笔记。

加载好跟踪之后，记得在 *Trace* 菜单中点击 **Load Symbols**，除非你已经在 UIforETW 的设置里启用了「**Load symbols automatically after trace load**」。

这次的示例捕获了我在 Visual Studio 中查看编译警告时遇到的卡顿。过程是：我反复按 F8 浏览编译警告，结果按到第三次 F8 后，就遭遇了一次大约六秒的停顿。我们在 *Trace information* 中记录了这些信息，以便后续分析。这样的信息在诊断性能问题时非常宝贵。

---

## 找到卡顿的起始点

当用 WPA 10 打开这个跟踪时，你应该会看到名为「**Generic Events Randomascii Chrome and Multi Events**」的图表和表格在最上面。如果没有看到，可以去 UIforETW 的设置对话框中点击「**Copy startup profiles**」，然后重新加载跟踪。使用合适的启动配置文件会让分析过程简单很多。

在 *Generic Events* 表格中，你可以依次展开：UIforETW、Multi-Input、Keyboard、Keydown，就能看到 20 个键盘事件。按 F7 键是用来编译项目，而那三个 F8 键分别对应了跳转到不同的警告信息。我们知道卡顿是从第三次按 F8（下图选中的那条记录）开始，因此可知卡顿从跟踪的第 6.5 秒开始（对应蓝色竖线处）：

![](https://randomascii.wordpress.com/wp-content/uploads/2015/09/image18.png)

我们已经估计这次卡顿大约持续了 6 秒，但还可以更精确地确定其结束时间点。

---

## 确定卡顿持续时间

在 WPA 的 *Graph Explorer* 窗口中，打开 *System Activity* 下的 **UI Delays** 图表，就能看到更准确的信息。只要线程长时间没有处理消息（大于 200 毫秒），`Microsoft-Windows-Win32k` 提供程序就会发出一条事件，这些事件会在 **UI Delays** 图表中展示出来。下图所示，`devenv.exe` 有一次连续 5,469 毫秒没有处理消息，其中 3,172 毫秒时间里消息队列里明明有输入消息却被忽略了。

![](https://randomascii.wordpress.com/wp-content/uploads/2015/09/image19.png)

表格中还会展示进程 ID（9104）和 UI 线程的线程 ID（10364）。要分析一次空闲卡顿（idle hang）就必须知道是哪个进程、哪个线程在等，这些信息就显得至关重要。

---

## 缩小范围，找到根因

分析空闲卡顿时，需要选中整段卡顿的时间区间，尤其要包含卡顿结束的时间点。多选一些时间总比少选要好，万一遗漏到结束时的关键事件就很麻烦。这个区间可以用鼠标拖选或者在 **UI Delays** 图表上直接右键点击相应的 **MsgCheck Delay** 条，再选择 **Zoom** 进行放大。

---

## 谁唤醒了谁？

如果一个线程没有在运行，而后来又开始运行，那一定有一次上下文切换（context switch）让它重新获得执行权。这个上下文切换会记录在 ETW 跟踪文件中，并且还带有一堆有用的信息。其中包括：

-   新进程名和线程 ID
-   线程恢复时的调用栈（实际上就是线程进入等待时的那条栈）
-   线程本次未运行的持续时长
-   如果线程在等待某个同步原语，还会记录哪个线程将其唤醒

这点非常关键。一次上下文切换告诉我们：线程是怎么被唤醒的，等待了多长时间，又是谁把它唤醒的。这也是为什么要确保我们在选区内包含「卡顿结束」的部分。只有这样，才能抓住那个真正令线程「复活」的上下文切换事件。

**CPU Usage (Precise)** 表格里就包含上下文切换的信息。用 UIforETW 的启动配置文件打开跟踪时，默认只显示图表。要做 Wait Analysis，我们需要在对应图表上点击「**Display Graph and Table**」，把表格也显示出来：

![](https://randomascii.wordpress.com/wp-content/uploads/2015/09/image20.png)

接下来，在表格里展开 **New Process** 下的 `devenv.exe (9104)`，并找到「New Thread Id 10364」。可以看见该线程在 5.469 秒的时间窗口里只消耗了 111.7 毫秒的 CPU 时间，这一下我们就知道这是一次「空闲导致的卡顿」，而不是线程在执行大量计算导致的卡顿。

分清什么时候应该用 Wait Analysis（分析线程空闲导致的卡顿）和什么时候用 CPU Usage 分析（分析线程繁忙导致的卡顿）非常关键。如果你试图用 CPU 使用率分析一个空闲线程，就会得到毫无意义的结果。

> 注意，大多数情况下线程处于空闲状态是完全正常的。大多数线程就应该空闲。之所以这一次空闲「不正常」，是因为它是 Visual Studio 的 UI 线程，而且在这 5.469 秒里都没有处理任何消息，导致用户界面失去响应。

`devenv.exe` 的 UI 线程在这个区间总共发生了 47 次上下文切换，我们要找的是那次让它重新从最长空闲中醒来的上下文切换，所以需要对表格按「Time Since Last」进行排序。正如我在 [这篇文章](https://randomascii.wordpress.com/2012/05/11/the-lost-xperf-documentationcpu-scheduling/)里解释过的，「Time Since Last」代表了线程再次获得 CPU 前已经被挂起了多长时间。UIforETW 的配置文件默认会列出两个「Time Since Last」列：一个用 Sum 聚合，一个用 Max 聚合。当你想找某个调用栈的所有上下文切换总共花了多长空闲时间时，可以用 Sum；当你想找一次单独的、时长最长的上下文切换时，可以用 Max。对于我们的例子，用哪个都行；不过我建议大家平时多尝试一下这两种。

如果用右箭头逐级展开（从第一项开始一直右键或右箭头钻取），我们会看到只有一次上下文切换（Count=1）对应了线程「空闲 5.341 秒后」重新获得 CPU 的时刻——这就是我们的卡顿。表中的「NewThreadStack」信息显示线程是从 `_RtlUserThreadStart` 一直传到若干 VS 的内部函数，这些函数调用顺序都显示在调用栈里。Microsoft 为 Visual Studio 的大部分代码都提供了符号表，所以我们能看到大约五十行之后才进入一些「更有价值的细节」：

![](https://randomascii.wordpress.com/wp-content/uploads/2015/09/image21.png)

这里清晰可见：就是这一次上下文切换（Count=1）导致 Visual Studio 的 UI 线程整整等待了 5.202 秒，真是一目了然。

往调用栈更底层看，我们会发现 `ntoskrnl.exe` 调用了 `FLTMGR.SYS`，紧接着是 `mup.sys!MupiCallUncProvider`（以及最终出现的 `WaitForSingleObject` 调用）——仔细想想这意味着什么？

![](https://randomascii.wordpress.com/wp-content/uploads/2015/09/image22.png)

如果在最底部继续往右滚动，展开 **Readying Process/Thread Id/Stack**，就能看到是哪个线程把该线程唤醒的：

![](https://randomascii.wordpress.com/wp-content/uploads/2015/09/image23.png)

Readying Process/Thread Id/Stack 表示「使等待线程进入就绪状态的线程」，也就是满足了等待条件的线程。也可能是锁、事件、另一个线程或者其他同步操作。不过，如果线程是因为定时器超时被唤醒，那么 Readying Process/Thread Id 就没有意义。定时器超时是通过硬件中断实现的，中断服务例程（ISR）会调度一个延迟过程调用（DPC），而那个 DPC 会在某个现有线程的上下文里执行，就像[寄生体](https://en.wikipedia.org/wiki/Invasion_of_the_Body_Snatchers_\(1978_film\))一样，它利用宿主线程去唤醒其他线程，所以此时显示的 Readying Process/Thread 并不是「真正」的唤醒者。进行 Wait Analysis 时，如果你看到 **Ready Thread in DPC** 为 True，就要忽略 Readying Process/Thread，正如我在这个 [Twitter 线程](https://twitter.com/BruceDawson0xB/status/1186533234345037829)里讨论过的那样。

我们可以看到是 System 进程下的线程（ID 5880）在 `IopfCompleteRequest` 中调用了 MUP.SYS 里的代码。要是你知道 MUP.SYS 是干什么的，这会进一步提示卡顿和网络 I/O 有关。不过即使不知道，你也能看到在 Visual Studio 调用了 `CreateFileW` 之后，花了很长时间才返回。

---

## 其他线程呢？

在我们的选区范围内，devenv.exe 里还有很多线程在大部分时间里都处于空闲状态。为什么不看看它们？

这里需要明白一点：**Sum:Time Since Last** 只表示「线程挂起了多长时间」。空闲本身并不可怕，只有当线程本该执行某些任务却一直空闲时，才会导致卡顿。对于一个多线程应用而言，如果机器只有四个核心，那剩余大部分线程大多数时间都应该是空闲的，否则系统就会被彻底占满。

我们之所以关注线程 10364，是因为（根据 MsgCheckDelay 事件）它是 UI 线程，并且它在这 5.469 秒中没有处理任何消息，导致用户界面卡死。这就是我们分析的重点所在。

---

## 查看 File I/O Summary

既然我们已经知道卡顿跟文件 I/O 有关，下一步就该看看这段时间内到底发生了哪些文件 I/O。幸运的是，UIforETW 同样记录了这部分信息。

在 WPA 的 **Graph Explorer** 中，找到 **Storage** 分类，然后打开 **File I/O** 图表，并显示汇总表。如果你把 **View Preset** 切换为 **Count by Process, Thread, Type**，然后依次展开 Process `devenv.exe (9104)`，Thread 10364，并按持续时间（Duration）排序，用右箭头逐级钻取，就很容易找到那次耗时很长的 I/O 操作。

通过滚动到 **File Path** 列，你就能看到类似下面的输出（截图内容很多，这里就只能截一部分了），点击图片可以查看大图：

![](https://randomascii.wordpress.com/wp-content/uploads/2015/09/image24.png)

可以看到，有一次「Create file」操作来自于 `devenv.exe` 的线程 10364，耗时 5.342 秒，试图打开路径 `\\\\\\\\Perforce\\\\main`，最终报告「网络路径无法找到」。

嗯，就在这里了。

也就是说，Visual Studio 想要去打开一个并不存在的网络文件，结果有时候就会触发 5.342 秒的网络超时，因此造成了界面卡顿。

卡顿剩余的时间花在了其他一些小的上下文切换和 CPU 时间上，总体加起来就得到了那 5.469 秒。真正导致线程长时间挂起的就是这 5.342 秒的 `CreateFile` 操作。

---

## 卡顿真正原因是什么？

这个文件名非常奇怪，完整路径其实是：

```
\\\\Perforce\\main\\src\\Lib\\Public\\sharedstuff.lib#127 – opened for edit
```

乍一看就不像是一个正常的文件路径，更像 Perforce 的输出信息——只不过它把原先 Perforce 中的斜杠换成了反斜杠。而事实上，这正是发生的情况。 我当时在 Valve 工作，会将编译结果上传到 Perforce，所以在构建脚本里加了一个预构建步骤去检查这些文件是否已被签出（check out）。Perforce 的命令行输出就包含了这样一句带有「opened for edit」的提示。

而 Visual Studio 又「热心地」把它当作潜在的文件路径来处理，将里面的「/」反转成了「\\」并认为这代表了 \\\\perforce\\main 上的文件名。由于这是按下 F8 后发生的事情，所以说明 VS 认为这是一条和警告或错误相关的路径，尝试去跳转过去。

于是就出现了调用栈上的 `CResultList::AttemptToNavigate`，一切都对上了。

---

## 结论

知道原因后，我在预构建脚本中加了一行 sed 命令，把输出内容重新格式化，让 VS 不再识别它为文件路径。这样一来，不仅避免了那次卡顿，也让 F8 可以真正跳转到真正需要关注的错误或警告信息上。sed 的具体用法非常简单，比如把「//」替换掉，把「...」替换成「—」：

```
sed -e s!//!! -e s!\\.\\.\\.!—! 
```

这样就把输出从下面这种易引发卡顿的文本（VS 解析为路径，进而触发网络 I/O）：

![](https://randomascii.wordpress.com/wp-content/uploads/2012/05/image9.png)

变成了对 VS 来说「安全」的文本（VS 不会当它是路径）

![](https://randomascii.wordpress.com/wp-content/uploads/2012/05/image10.png)

我也把这个问题报告给了 Visual Studio 团队。像这样带上 xperf 跟踪文件的 bug 报告会非常有力，因为我能在报告里非常明确地指出问题所在，并向他们提供跟踪文件以供进一步确认。就像 minidump 文件对报告崩溃问题很有效一样，xperf 跟踪文件对报告性能问题也同样强大。Visual Studio 团队后来在 VS2012 中修复了这个问题：VS 输出窗口的解析器会忽略 UNC 路径，不再因为这些「假路径」阻塞 UI。

顺带一提，`mup.sys` 是处理网络文件 I/O 的驱动程序。如果在调用栈或「Ready Thread Stack」里看到它，就意味着网络 I/O 可能是造成卡顿的罪魁祸首。在 UI 线程上进行文件 I/O 本就危险，而进行网络文件 I/O 更是高风险，这些都容易导致卡顿。

## 等待链

有些 Wait Analysis 的场景会比这次更复杂。比如，在某些游戏中，主线程可能卡顿几百毫秒，是因为它等待了某个信号量（semaphore）或临界区（critical section），而释放该同步对象的另一个线程又在等待别的东西，可能链式传递好多次。在这种场景下，「Readying Thread」就非常关键，因为它代表了谁释放了同步对象。只要知道是谁阻塞了主线程，你就可以去看看那个线程是在忙（CPU 使用率过高）还是也在等别的锁（空闲等待）。通常排查一两层就能找到根本原因，不过我最近遇到过一次跨四个进程、六次上下文切换才找到操作系统调度问题的案例。

当顺着等待链往下查时，记得一定要关注事件的发生顺序。如果线程 1234 在 10.5 秒时被线程 5678 唤醒，那么 5678 在 10.5 秒之后的其他上下文切换或 CPU 活动就和 1234 的等待链无关了，因为唤醒已经发生了，那之后再发生的事情不会影响这个等待。

对于 CPU 活动，通过选择相应的时间范围就能过滤掉无关内容；对于上下文切换，则需要一直展开查看「SwitchInTime (s)」这一列，该列记录了上下文切换发生的实际时间。

最后要提醒的是，如果你用自旋锁或自己实现的同步原语（如 `CSuperFastCriticalSection`）来「忙等」，这种 Wait Analysis 就无法帮上忙了。因为操作系统的同步原语都内置了相应的 ETW 事件，可以让我们「完美」跟踪等待链，但自定义锁就没有这种系统级别的跟踪。即使你自定义的锁可能「速度更快」，其实通常也没快多少，而失去 Wait Analysis 带来的洞察力，代价反而更大。**能进行可视化分析，往往比小幅提升性能更重要。**

## 难道别的分析器也能做同样的事情？

采样分析器和插桩式分析器也许能告诉你程序在空闲时停留在哪个函数上，但它们通常告诉不了你为何空闲、具体在等谁。只有通过跟踪一条条唤醒线程的线索，并结合其他信息，才能确定导致空闲等待的真正根源。

另外，xperf 还能以「连续捕获（continuous capture）」模式运行，不断地把系统活动记录到一个环形缓冲区里，当你观察到问题时再把缓冲区写到磁盘，之后进行离线分析。这是非常灵活的做法。

## Wait Analysis 并不是「照着菜谱做饭」

做菜很多时候要精确按配方来，一旦乱改就容易失败；但 Wait Analysis 更像是解决谜题，需要灵活思考、跳出固有思路，并且对整个系统有深入理解。你要理解上下文切换、思考哪些空闲时间是正常的、哪些是不正常的；要分辨什么时候看 CPU Usage、什么时候看等待链；有时还需要摸索出全新角度的分析手段或表格汇总方式。确实不容易，但一旦掌握了这些技巧，就能解决大多数开发者无法处理的难题。

## 另一种观点

如果你想了解更多关于 xperf 处理卡顿的案例，可以看看 Trey Nash 的这篇 [等待分析文章](http://devproconnections.com/development/use-xperfs-wait-analysis-application-performance-troubleshooting)。如果你想在 Linux 上做类似的分析，请参阅 Brendan Gregg 关于 [Off-CPU 分析](http://www.brendangregg.com/offcpuanalysis.html)的文章。', 'win', NULL, 'published', 0, 6118, 22, 204, 1737703403, 1737703403, 1737703405);
INSERT INTO posts (slug, title, excerpt, body, tag_id, series, status, pinned, words, read_time, views, published_at, created_at, updated_at) VALUES ('etw-heap-tracingevery-allocation-recorded', '【译】ETW 堆跟踪 – 每个分配都被记录', '原文： https://randomascii.wordpress.com/2015/04/27/etw heap tracingevery allocation recorded/ Windows 的事件跟踪 (ETW，亦称为 xperf) 通常用于监控 CPU 使用情况，通过采样分析器及其记录上下文切换的能力来实现', '> 原文：
> 
> https://randomascii.wordpress.com/2015/04/27/etw-heap-tracingevery-allocation-recorded/

Windows 的事件跟踪 (ETW，亦称为 [xperf](https://randomascii.wordpress.com/category/xperf/)) 通常用于监控 CPU 使用情况，通过采样分析器及其记录上下文切换的能力来实现。此外，ETW 还用于监控文件 I/O、磁盘 I/O，有时还会记录注册表访问，当然还包括 GPU 活动、窗口聚焦、UI 延迟、进程生命周期等。简而言之，ETW 被用于多种不同的用途，通常通过相同的配置在整个系统中进行记录。

而堆分析则有所不同。即使是那些熟悉 ETW 跟踪记录奇技淫巧的开发人员，也可能会发现如何进行堆分析有些令人畏惧。我一直推迟写这篇文章，因为讲解如何记录堆跟踪并分析它是非常繁琐的工作。不过，随着 UIforETW 的发布，记录 ETW 堆跟踪几乎变得非常简单，分析它也变得更加轻松。另外，近期（大约在 2016/2017 年）ETW 的一些更新，使得记录堆跟踪变得更加简便。

作为一个额外的好处，系统内存列表和所有进程的 VirtualAlloc 调用都会在 UIforETW 追踪中记录，并且会在本文底部进行简单的文档说明，还可以选择记录轻量级的内存分析堆栈信息。

简而言之，ETW 堆跟踪使得记录和分析任何使用 Windows 堆的应用程序（默认的 VC++ 内存分配器）的每个分配和释放变得非常容易。这使得调查内存泄漏、分配波动以及其他堆问题成为可能。

> 本文在 2015 年 6 月进行了更新，因为现在支持同时对多个进程名称进行堆分析。

> 本文在 2018 年 10 月进行了更新，增加了新的堆跟踪（PID 和启动-跟踪）及分析选项。

请注意，如果你只想记录所有未释放的分配的大小和堆栈信息，那么 *堆快照* 是一个更高效的选项，可以记录数周的分配信息。它们的文档请参见 [此处](https://randomascii.wordpress.com/2019/10/27/heap-snapshots-tracing-all-heap-allocations/)。

> （参见 UIforETW [公告文章](https://randomascii.wordpress.com/2015/04/14/uiforetw-windows-performance-made-easier/) 获取更多详细信息）

# 堆跟踪的不同之处

ETW 堆跟踪不会在全局启用，因为它的开销较大。仅仅为一个进程记录每个堆分配的堆栈信息，数据量就可能巨大，而如果对所有进程都启用堆跟踪，那将是不可承受的。因此，ETW 堆跟踪是为特定进程启用的。启用的方式有三种：

1.  按进程名称进行跟踪

启用堆跟踪的第一种方式（UIforETW 支持最长的方式）是通过指定要跟踪的进程名称，然后记录堆事件。这是一个两步操作。

步骤 1：在 *Image File Execution Options* 中为每个要跟踪的进程名称创建并设置一个 *TracingFlags* 注册表项，值为 ''''1''''，这样 Windows 堆就会在启动时配置自己以进行堆跟踪。正如 *Image File Execution Options* 中的所有选项一样，这些设置不会影响已运行的进程，只有在设置注册表键值后启动的进程才会受到影响。

![](https://media.frendguo.com/2025/02/b1d51738-2c8a-4ed8-859a-d2c848865c68.png)

步骤 2：通过“ -heap -Pids 0”指令创建一个额外的 ETW 会话。此会话将记录启动时已经设置了 *TracingFlags* 注册表项为 ''''1'''' 的进程的信息。

使用 UIforETW 时，你需要打开设置对话框并指定你的进程名称。默认情况下，它是 Chrome.exe，因为我最初为 Chrome 编写了 UIforETW，但你可以将其更改为任何其他进程名称。*exe 后缀是必需的，且如果要指定多个进程名称，请用分号隔开：*

![](https://media.frendguo.com/2025/02/eb1b30f3-51c3-4f46-b943-7f478cf55ccc.png)

然后，设置跟踪模式为 *Heap tracing to file*。一旦这样做，就会为指定的进程创建并将 *TracingFlags* 设置为 1。当退出 UIforETW 或更改跟踪模式时，该值会被重置为 0。这意味着，只要选择了 *Heap tracing to file*，你就可以启动要堆跟踪的进程。

为了实际开始记录堆跟踪信息，你需要点击 *Start Tracing*。

![](https://media.frendguo.com/2025/02/6b7f4663-b663-4d79-a19d-1758467062bf.png)

理解了这个两步操作后，你就知道如何使用它了。你需要设置 *Heap-profiled process* 名称，并选择 *Heap tracing to file*，然后启动你想要跟踪的进程。在任何数据被记录之前，你需要开始跟踪。无论你是先启动进程还是后启动进程，都决定了是否记录进程启动时的分配。

是的，这也适用于多个进程。当我分析 Chrome 时，所有 Chrome 进程的堆数据都会被记录——只要它们是在设置了注册表键之后启动的。它甚至支持多个不同的进程名称。

---

2.  按 PID 进行跟踪

第二种启用堆跟踪的方式是指定一个或多个已经在运行的进程的 PID（最多支持两个）。在 UIforETW 设置对话框中输入一个或两个 PID，并用分号分隔，然后将堆跟踪类型设置为 *H**eap tracing to file*，开始跟踪时就会记录指定进程的堆数据。这个方法非常简单，但有一些缺点，比如不能记录进程启动时的分配信息，并且当 PID 发生变化时需要手动调整。以下是设置对话框的示例：

![](https://media.frendguo.com/2025/02/2e8b5c61-1f71-4e7d-9a22-d41346c4279d.png)

---

3.  启动并跟踪一个进程

第三种方式是通过 ETW 启动你想要跟踪的进程，以确保从该进程启动时就开始堆跟踪，而不涉及其他进程。使用这种方法时，你需要在堆跟踪进程字段中输入要启动的可执行文件的完整路径。然后，当你开始堆跟踪时，这个可执行文件将会启动并被跟踪。

![](https://media.frendguo.com/2025/02/40d86cde-c9fb-46ec-99fd-5a1b1f9e50a1.png)

# 分析堆跟踪

记录完场景后（最好保持短时间记录，避免生成体积庞大且难以操作的跟踪数据），你可以像往常一样保存跟踪缓冲区。跟踪的名称通常是类似“date\_time\_bruced\_notepad\_heap.etl”的格式，这有助于提醒你记录了什么数据。通常，你应该双击跟踪文件，将其加载到 Windows 性能分析器（WPA）中。

UIforETW 启动时的配置不会立即显示用于查看堆或内存数据的图表，因此你需要添加这些图表（并可选择保存为新的启动配置文件）。内存图表位于 *Memory* 部分的 *Graph Ex**plorer* 中，最应该添加的图表可能是 *Heap Allocations*。拖动它后，你会看到 WPA 默认的堆查看设置，虽然通常这些设置我认为并不适合。默认视图显示了一些通常不需要的列，例如 *Address* 和 *AllocTime*，而缺少了非常重要的列，例如 *Stack* 和 *Type*。为了得到更合适的默认设置，可以选择 *Randomascii Heap Analysis* 配置，得到如下界面：

![](https://media.frendguo.com/2025/02/986b5079-244c-4500-912f-9e1654e9ef61.png)

现在，你可以开始深入分析你的进程了。如果你想按堆进行分组，可以添加 *Handle* 列，但通常它的意义不大。

接下来的列是最重要且最不显眼的。在 ETW 内存分析中，有四种 *Type*（类型）表示的分配，它们是：

-   **AIFO** – 分配发生在时间范围内，释放发生在时间范围外：这些是那些在显示时间范围内分配但未在该范围内释放的内存块。它们可能在时间范围外被释放，或者可能从未被释放。当你深入分析这些内存块的堆栈时，*Count* 表示未释放的分配，*Size* 表示未释放的内存。
-   **AOFI** – 分配发生在时间范围外，释放发生在时间范围内：这些内存块的分配发生在时间范围外，释放发生在时间范围内。它们是 AIFO 的镜像，计算非释放分配的数量时，通常需要从 AIFO 中减去 AOFI。
-   **AOFO** – 分配和释放都发生在时间范围外：这些是存活时间无限的内存块——至少在显示的时间范围内如此。
-   **AIFI** – 分配和释放都发生在时间范围内：这些内存块是堆分析中的“飞蛾”——它们生得快，死得快，在显示的时间范围内分配和释放。

在 *Type* 列之后是 *Stack* 列，它的表现与往常相同。使用默认的 *Randomascii* 表格布局，你可以深入分析某种类型的分配，按你选择的列进行排序。

接着是 *Count* 列，它显示每行总结的分配数量。在 *Heap Allocations* 图表中，某进程的 *Count* 包括了在显示的时间范围内存活的所有分配。这个范围通常非常广，因此，除非你按 *Type* 分组，否则我认为 *Count* 列几乎无法提供有意义的解释。

*Impacting Size* 是“当前视口内堆使用量的变化”。这意味着，它总结了每行在显示的时间范围内，堆请求内存的总量。对于 AOFO 和 AIFI，这个值始终为零，因为 AOFO 表示在该时间范围内没有分配或释放，而 AIFI 表示在该时间范围内的分配和释放是配对的。对于 AIFO，这个数字就是分配的字节数，并且它将与 *Size* 一致。对于 AOFI，这个数字始终是 *Size* 的负值。*Impacting Size* 在你理解它后非常有用。即使没有使用 *Type* 列进行分组，它也是有意义的。

*Size* 列则显示了每行总结的总字节数，无论分配发生的具体时间。*Size* 和 *Impacting Size* 都是以请求的字节数衡量的，因此一字节的分配在这里显示为“1”，而不是它在堆中的实际占用空间。

## 其他堆图表

在进行堆跟踪时，还可以使用以下图表：

-   *Low Fragmentation Heap* 图表揭示了一些堆的内部细节，你可以深入探究这些信息。
-   *Heap Extents* 图表显示了进程使用的承诺内存量，可能有助于推测堆的效率等有用信息。但由于我缺乏足够的经验，无法深入分析这个图表。

## 其他内存图表

所有 UIforETW 图表中都记录了一些内存信息，因为 VIRT\_ALLOC 和 MEM\_INFO 提供者也会被记录：

-   *V**irtual Alloc* 图表显示了类似于堆图表的信息，包括具有与堆图表相同的 *Type* 列。通常默认设置不太好，因此可以使用 RandomAscii 配置来进行优化。需要注意的是，UIforETW 始终会记录所有进程的 VirtualAlloc 信息，因为你永远无法预知何时它会有用。当堆跟踪被记录时，每个 VirtualAlloc 调用也会记录堆栈信息，这使得分析数据更有价值。如果你在非堆跟踪时查看 VirtualAlloc 信息，则可能希望隐藏 \\\[empty\\\] Stack 列。

![](https://media.frendguo.com/2025/02/480bfd19-5c30-4e55-9faf-8115625b0dee.png)

值得指出的是，只有从进程启动时开始跟踪，你才能用 VirtualAlloc 数据得出该进程分配了多少内存；否则，你会错过许多 VirtualAlloc 调用，从而大大低估进程的内存消耗。

-   *Memory Utilization* 图表展示了大约每 0.5 秒采样一次的内存使用情况，显示了各种内存列表的情况，如 Active List、Zero 和 Free Lists、Standby Lists 等。有关这些列表的更多解释可以参考书籍或讲座，主要需要记住的是 *Standby Lists* 和 *Zero 和 Free Lists* 代表可用内存，如果它们过低（低于约 800 MB），Windows 将开始修剪工作集，这可能会在未来某个不确定的时间导致性能下降。

![](https://media.frendguo.com/2025/02/77264e17-b439-41ac-a0c2-9b5d833c8392.png)

在这里，我们可以看到 Zero 和 Free Lists 被暂时耗尽以满足某些短期内存需求，但在释放后又恢复到了过量的水平。

## 文档 == 好

在写这篇博文时，我意识到我已经不记得我当时是如何设计 UIforETW 堆跟踪的了。下次我忘记的时候，我会直接阅读这篇文章，而不是盯着源代码看，试图搞明白是如何运作的。在回顾的过程中，我发现了一个 bug，它已经在 [7c8e56d](https://github.com/google/UIforETW/commit/7c8e56d) 版本中修复，并对其他细节做了一些调整。

因此，确保你获得 UIforETW 的最新版本！

